/// Container RSS (resident set size) in GB, read from /proc/self/statm
/// (page count × page size). Returns 0.0 if unreadable (non-Linux). Used to
/// instrument the DiT-setup gap so a CPU-RAM OOM (full-DiT f32 dequant blowing
/// the 32Gi container) is visible in the logs before the OOM-killer fires.
#[cfg(not(target_arch = "wasm32"))]
fn proc_rss_gb() -> f64 {
    let Ok(statm) = std::fs::read_to_string("/proc/self/statm") else {
        return 0.0;
    };
    // Fields: size resident shared text lib data dt (in pages).
    let resident_pages: u64 = statm
        .split_whitespace()
        .nth(1)
        .and_then(|s| s.parse().ok())
        .unwrap_or(0);
    let page = 4096u64; // Linux default; close enough for a coarse RSS gauge.
    (resident_pages * page) as f64 / 1e9
}

/// Flushed marker for the DiT-setup gap: stamps stderr with `[gap] <marker>`
/// plus container RSS, then flushes so the LAST marker pinpoints a silent
/// hang/OOM. Pairs with `cuda_matmul::log_vram` for the VRAM side.
#[cfg(not(target_arch = "wasm32"))]
fn gap_marker(marker: &str) {
    use std::io::Write;
    eprintln!("[gap] {marker} (rss={:.2} GB)", proc_rss_gb());
    let _ = std::io::stderr().flush();
}

