#[derive(Debug, Clone, Copy, Serialize, Deserialize, PartialEq, Eq)]
#[serde(rename_all = "kebab-case")]
pub enum SpectralDenoiseColor {
    Brown,
    Pink,
    White,
    Violet,
}

impl SpectralDenoiseColor {
    pub fn parse_csv(raw: &str) -> Result<Vec<Self>, String> {
        raw.split(',')
            .map(str::trim)
            .filter(|entry| !entry.is_empty())
            .map(Self::parse)
            .collect()
    }

    fn parse(raw: &str) -> Result<Self, String> {
        match raw.trim().to_ascii_lowercase().as_str() {
            "brown" => Ok(Self::Brown),
            "pink" => Ok(Self::Pink),
            "white" => Ok(Self::White),
            "violet" => Ok(Self::Violet),
            other => Err(format!("invalid spectral denoise color {other:?}")),
        }
    }
}

#[derive(Debug, Clone, Copy, Serialize, Deserialize, PartialEq, Eq)]
#[serde(rename_all = "kebab-case")]
pub enum SpectralResidualQuantizer {
    None,
    Cubic,
    E8,
}

impl SpectralResidualQuantizer {
    pub fn parse(raw: &str) -> Result<Self, String> {
        match raw.trim().to_ascii_lowercase().as_str() {
            "none" => Ok(Self::None),
            "cubic" => Ok(Self::Cubic),
            "e8" => Ok(Self::E8),
            other => Err(format!("invalid spectral residual quantizer {other:?}")),
        }
    }
}

