pub fn require_visible_image_admission(report: &FluxTxt2ImgReport) -> Result<(), String> {
    if report.is_visible_image_admitted() {
        Ok(())
    } else {
        Err(format!(
            "FLUX txt2img did not produce an admitted prompt-faithful visible image: {}",
            report.blockers.join("; ")
        ))
    }
}

pub fn require_visible_carrier_or_image_admission(
    report: &FluxTxt2ImgReport,
) -> Result<(), String> {
    if report.is_visible_carrier_or_image_admitted() {
        Ok(())
    } else {
        Err(format!(
            "FLUX txt2img did not produce admitted carrier/image evidence: {}",
            report.blockers.join("; ")
        ))
    }
}

#[cfg(not(target_arch = "wasm32"))]
pub fn build_flux_clip_embedding_probe(
    knot_source: &str,
    knot: &KnotWeights,
    sidecar: &FluxTokenSidecar,
) -> Result<FluxEmbeddingProbe, String> {
    if sidecar.clip_ids.is_empty() {
        return Err("CLIP token ids are missing from token sidecar".to_string());
    }
    let token_tensor = fetch_knot_tensor_bytes_from_metadata(
        knot_source,
        &knot.metadata,
        knot.payload_offset,
        CLIP_TOKEN_EMBEDDING,
    )
    .map_err(|error| format!("fetch CLIP token embedding: {error}"))?;
    let position_tensor = fetch_knot_tensor_bytes_from_metadata(
        knot_source,
        &knot.metadata,
        knot.payload_offset,
        CLIP_POSITION_EMBEDDING,
    )
    .map_err(|error| format!("fetch CLIP position embedding: {error}"))?;

    if !token_tensor.info.tensor_type.eq_ignore_ascii_case("Q8_0") {
        return Err(format!(
            "{CLIP_TOKEN_EMBEDDING} must be Q8_0, got {}",
            token_tensor.info.tensor_type
        ));
    }
    if !position_tensor.info.tensor_type.eq_ignore_ascii_case("F32")
        && !position_tensor.info.tensor_type.eq_ignore_ascii_case("fp32")
    {
        return Err(format!(
            "{CLIP_POSITION_EMBEDDING} must be F32, got {}",
            position_tensor.info.tensor_type
        ));
    }

    let token_shape = expect_shape(&token_tensor.info.shape, CLIP_TOKEN_EMBEDDING, 2)?;
    let position_shape = expect_shape(&position_tensor.info.shape, CLIP_POSITION_EMBEDDING, 2)?;
    let vocab_size = token_shape[0];
    let hidden_dim = token_shape[1];
    if hidden_dim != CLIP_HIDDEN_DIM {
        return Err(format!(
            "{CLIP_TOKEN_EMBEDDING} hidden dim mismatch: expected {CLIP_HIDDEN_DIM}, got {hidden_dim}"
        ));
    }
    if position_shape[1] != hidden_dim {
        return Err(format!(
            "CLIP token/position hidden dims differ: {} vs {}",
            hidden_dim, position_shape[1]
        ));
    }
    let position_values =
        parse_f32_le_tensor(&position_tensor.bytes, position_shape[0] * position_shape[1])?;
    let stats = summarize_q8_rows_with_position(
        &token_tensor.bytes,
        &position_values,
        &sidecar.clip_ids,
        vocab_size,
        hidden_dim,
        position_shape[0],
    )?;
    let negative_stats = if sidecar.negative_clip_ids.is_empty() {
        None
    } else {
        Some(summarize_q8_rows_with_position(
            &token_tensor.bytes,
            &position_values,
            &sidecar.negative_clip_ids,
            vocab_size,
            hidden_dim,
            position_shape[0],
        )?)
    };

    Ok(FluxEmbeddingProbe {
        status: "ready".to_string(),
        detail: "CLIP token and position embeddings materialized from KNOT tensor bytes"
            .to_string(),
        token_count: sidecar.clip_ids.len(),
        hidden_dim,
        values: stats.values,
        finite: stats.finite,
        mean: stats.mean,
        std: stats.std,
        rms: stats.rms,
        hash: stats.hash,
        negative_hash: negative_stats.as_ref().map(|stats| stats.hash),
        prompt_sensitive: negative_stats
            .as_ref()
            .map(|negative| negative.hash != stats.hash)
            .unwrap_or(stats.hash != 0),
        fetched_tensors: vec![token_tensor.name, position_tensor.name],
    })
}

#[cfg(not(target_arch = "wasm32"))]
pub fn build_flux_t5_embedding_probe(
    knot_source: &str,
    knot: &KnotWeights,
    sidecar: &FluxTokenSidecar,
) -> Result<FluxEmbeddingProbe, String> {
    if sidecar.t5_ids.is_empty() {
        return Err("T5 token ids are missing from token sidecar".to_string());
    }
    let tensor = fetch_knot_tensor_bytes_from_metadata(
        knot_source,
        &knot.metadata,
        knot.payload_offset,
        T5_SHARED_EMBEDDING,
    )
    .map_err(|error| format!("fetch T5 shared embedding: {error}"))?;
    if !tensor.info.tensor_type.eq_ignore_ascii_case("Q8_0") {
        return Err(format!(
            "{T5_SHARED_EMBEDDING} must be Q8_0, got {}",
            tensor.info.tensor_type
        ));
    }
    let shape = expect_shape(&tensor.info.shape, T5_SHARED_EMBEDDING, 2)?;
    if shape != [T5_VOCAB_SIZE, T5_HIDDEN_DIM] {
        return Err(format!(
            "{T5_SHARED_EMBEDDING} shape mismatch: expected [{T5_VOCAB_SIZE}, {T5_HIDDEN_DIM}], got {:?}",
            shape
        ));
    }
    let stats = summarize_q8_rows(
        &tensor.bytes,
        &sidecar.t5_ids,
        T5_VOCAB_SIZE,
        T5_HIDDEN_DIM,
    )?;
    let negative_stats = if sidecar.negative_t5_ids.is_empty() {
        None
    } else {
        Some(summarize_q8_rows(
            &tensor.bytes,
            &sidecar.negative_t5_ids,
            T5_VOCAB_SIZE,
            T5_HIDDEN_DIM,
        )?)
    };

    Ok(FluxEmbeddingProbe {
        status: "ready".to_string(),
        detail: "T5 shared embeddings materialized from KNOT tensor bytes".to_string(),
        token_count: sidecar.t5_ids.len(),
        hidden_dim: T5_HIDDEN_DIM,
        values: stats.values,
        finite: stats.finite,
        mean: stats.mean,
        std: stats.std,
        rms: stats.rms,
        hash: stats.hash,
        negative_hash: negative_stats.as_ref().map(|stats| stats.hash),
        prompt_sensitive: negative_stats
            .as_ref()
            .map(|negative| negative.hash != stats.hash)
            .unwrap_or(stats.hash != 0),
        fetched_tensors: vec![tensor.name],
    })
}

#[cfg(not(target_arch = "wasm32"))]
pub fn build_flux_t5_exact_prefix_forward_probe(
    knot_source: &str,
    knot: &KnotWeights,
    sidecar: &FluxTokenSidecar,
    prefix_tokens: usize,
) -> Result<FluxEmbeddingProbe, String> {
    Ok(build_flux_t5_exact_prefix_forward_state(knot_source, knot, sidecar, prefix_tokens)?.probe)
}

#[cfg(not(target_arch = "wasm32"))]
pub fn build_flux_t5_exact_prefix_forward_state(
    knot_source: &str,
    knot: &KnotWeights,
    sidecar: &FluxTokenSidecar,
    prefix_tokens: usize,
) -> Result<FluxT5ExactPrefixForwardState, String> {
    if sidecar.t5_ids.is_empty() {
        return Err("T5 token ids are missing from token sidecar".to_string());
    }
    let prefix_token_limit = validate_t5_prefix_tokens(prefix_tokens)?;
    let prefix_len = sidecar.t5_ids.len().min(prefix_token_limit);
    let prompt_ids = &sidecar.t5_ids[..prefix_len];
    let prompt_embedding = materialize_t5_embeddings(knot_source, knot, prompt_ids)?;
    let weights = load_t5_block0_prefix_weights(knot_source, knot, prefix_len)?;
    let config = FluxT5PrefixConfig {
        seq_len: prefix_len,
        hidden_dim: T5_HIDDEN_DIM,
        heads: T5_HEADS,
        head_dim: T5_HEAD_DIM,
        ff_dim: T5_FFN_DIM,
        eps: T5_LAYER_NORM_EPS,
    };
    let prompt_output = t5_exact_prefix_forward(&prompt_embedding.values, &weights, config)?;
    let stats = summarize_f32s(&prompt_output)?;
    if stats.finite != stats.values || stats.rms == 0.0 {
        return Err("T5 exact-prefix output must be finite and nonzero".to_string());
    }

    let negative_stats = if sidecar.negative_t5_ids.is_empty() {
        None
    } else {
        let negative_len = sidecar.negative_t5_ids.len().min(prefix_token_limit);
        let negative_ids = &sidecar.negative_t5_ids[..negative_len];
        let negative_embedding = materialize_t5_embeddings(knot_source, knot, negative_ids)?;
        let negative_config = FluxT5PrefixConfig {
            seq_len: negative_len,
            hidden_dim: T5_HIDDEN_DIM,
            heads: T5_HEADS,
            head_dim: T5_HEAD_DIM,
            ff_dim: T5_FFN_DIM,
            eps: T5_LAYER_NORM_EPS,
        };
        let negative_output = if negative_len == prefix_len {
            t5_exact_prefix_forward(&negative_embedding.values, &weights, negative_config)?
        } else {
            let negative_weights = load_t5_block0_prefix_weights(knot_source, knot, negative_len)?;
            t5_exact_prefix_forward(&negative_embedding.values, &negative_weights, negative_config)?
        };
        Some(summarize_f32s(&negative_output)?)
    };
    let prompt_sensitive = negative_stats
        .as_ref()
        .map(|negative| negative.hash != stats.hash)
        .unwrap_or(stats.hash != 0);
    if !prompt_sensitive {
        return Err("T5 exact-prefix output is not prompt-sensitive".to_string());
    }

    Ok(FluxT5ExactPrefixForwardState {
        probe: FluxEmbeddingProbe {
            status: "ready".to_string(),
            detail: format!(
                "native T5 encoder block-0 exact prefix forward ready over {prefix_len} token(s)"
            ),
            token_count: prefix_len,
            hidden_dim: T5_HIDDEN_DIM,
            values: stats.values,
            finite: stats.finite,
            mean: stats.mean,
            std: stats.std,
            rms: stats.rms,
            hash: stats.hash,
            negative_hash: negative_stats.as_ref().map(|stats| stats.hash),
            prompt_sensitive,
            fetched_tensors: t5_prefix_fetched_tensors(),
        },
        prompt_output,
    })
}

/// Run the FULL FLUX T5-XXL encoder stack (all 24 blocks + final RMSNorm) over the
/// complete prompt sequence (no 8-token prefix cap), returning both a probe and the
/// `[seq, 4096]` hidden states. This is the Phase-0 conditioning path: it replaces
/// the block-0 prefix gate for T5; the CLIP path is unchanged.
///
/// The sequence length is the full T5 token count, capped at [`T5_MAX_SEQUENCE_LEN`].
#[cfg(not(target_arch = "wasm32"))]
pub fn build_flux_t5_full_stack_forward_state(
    knot_source: &str,
    knot: &KnotWeights,
    sidecar: &FluxTokenSidecar,
) -> Result<FluxT5ExactPrefixForwardState, String> {
    if sidecar.t5_ids.is_empty() {
        return Err("T5 token ids are missing from token sidecar".to_string());
    }
    let seq_len = sidecar.t5_ids.len().min(T5_MAX_SEQUENCE_LEN);
    let prompt_ids = &sidecar.t5_ids[..seq_len];
    let prompt_embedding = materialize_t5_embeddings(knot_source, knot, prompt_ids)?;
    let config = FluxT5PrefixConfig {
        seq_len,
        hidden_dim: T5_HIDDEN_DIM,
        heads: T5_HEADS,
        head_dim: T5_HEAD_DIM,
        ff_dim: T5_FFN_DIM,
        eps: T5_LAYER_NORM_EPS,
    };
    let prompt_output =
        run_t5_full_stack_streaming(knot_source, knot, &prompt_embedding.values, config)?;
    let stats = summarize_f32s(&prompt_output)?;
    if stats.finite != stats.values || stats.rms == 0.0 {
        return Err("T5 full-stack output must be finite and nonzero".to_string());
    }

    let negative_stats = if sidecar.negative_t5_ids.is_empty() {
        None
    } else {
        let negative_len = sidecar.negative_t5_ids.len().min(T5_MAX_SEQUENCE_LEN);
        let negative_ids = &sidecar.negative_t5_ids[..negative_len];
        let negative_embedding = materialize_t5_embeddings(knot_source, knot, negative_ids)?;
        let negative_config = FluxT5PrefixConfig {
            seq_len: negative_len,
            ..config
        };
        let negative_output = run_t5_full_stack_streaming(
            knot_source,
            knot,
            &negative_embedding.values,
            negative_config,
        )?;
        Some(summarize_f32s(&negative_output)?)
    };
    let prompt_sensitive = negative_stats
        .as_ref()
        .map(|negative| negative.hash != stats.hash)
        .unwrap_or(stats.hash != 0);
    if !prompt_sensitive {
        return Err("T5 full-stack output is not prompt-sensitive".to_string());
    }

    Ok(FluxT5ExactPrefixForwardState {
        probe: FluxEmbeddingProbe {
            status: "ready".to_string(),
            detail: format!(
                "native T5-XXL full encoder stack ({T5_NUM_BLOCKS} blocks) forward ready over {seq_len} token(s)"
            ),
            token_count: seq_len,
            hidden_dim: T5_HIDDEN_DIM,
            values: stats.values,
            finite: stats.finite,
            mean: stats.mean,
            std: stats.std,
            rms: stats.rms,
            hash: stats.hash,
            negative_hash: negative_stats.as_ref().map(|stats| stats.hash),
            prompt_sensitive,
            fetched_tensors: t5_full_stack_fetched_tensors(),
        },
        prompt_output,
    })
}

/// Slice the full-stack T5 hidden states down to the prefix that the FLUX DiT
/// carrier path currently consumes. The carrier still operates over the first
/// `min(seq, t5_prefix_tokens<=MAX)` text tokens; Phase 0 only changes WHERE those
/// hidden states come from (full 24-block stack instead of block-0 only). Returns
/// `[prefix_len, T5_HIDDEN_DIM]` taken from the head of `full_stack_output`.
#[cfg(not(target_arch = "wasm32"))]
pub fn flux_t5_dit_prefix_slice(
    full_stack_output: &[f32],
    sidecar: &FluxTokenSidecar,
    t5_prefix_tokens: usize,
) -> Result<Vec<f32>, String> {
    if sidecar.t5_ids.is_empty() {
        return Err("T5 token ids are missing from token sidecar".to_string());
    }
    let prefix_token_limit = validate_t5_prefix_tokens(t5_prefix_tokens)?;
    let seq_len = sidecar.t5_ids.len().min(T5_MAX_SEQUENCE_LEN);
    let prefix_len = seq_len.min(prefix_token_limit);
    if prefix_len == 0 {
        return Err("T5 prefix is empty after applying token limit".to_string());
    }
    let expected = seq_len * T5_HIDDEN_DIM;
    if full_stack_output.len() != expected {
        return Err(format!(
            "T5 full-stack output length mismatch: expected {expected}, got {}",
            full_stack_output.len()
        ));
    }
    Ok(full_stack_output[..prefix_len * T5_HIDDEN_DIM].to_vec())
}

#[cfg(not(target_arch = "wasm32"))]
/// DEBUG: return the sovereign FLUX CLIP pooled vector [768] for given clip_ids,
/// for numeric cross-check (cosine) against a HF CLIPTextModel pooled output.
/// Mirrors the conditioning path used by `build_flux_clip_forward_probe`.
#[cfg(not(target_arch = "wasm32"))]
pub fn debug_flux_clip_pooled(
    knot_source: &str,
    knot: &KnotWeights,
    clip_ids: &[i64],
) -> Result<Vec<f32>, String> {
    if clip_ids.is_empty() {
        return Err("CLIP token ids are empty".to_string());
    }
    let tables = load_clip_embedding_tables(knot_source, knot)?;
    let embedding = materialize_clip_embeddings(&tables, clip_ids)?;
    let encoder = FluxClipTextEncoder::load(knot_source, knot)?;
    let forward = encoder.forward(&embedding.values, clip_ids)?;
    Ok(forward.pooled)
}

pub fn build_flux_clip_forward_probe(
    knot_source: &str,
    knot: &KnotWeights,
    sidecar: &FluxTokenSidecar,
) -> Result<FluxClipForwardProbe, String> {
    if sidecar.clip_ids.is_empty() {
        return Err("CLIP token ids are missing from token sidecar".to_string());
    }
    let tables = load_clip_embedding_tables(knot_source, knot)?;
    let prompt_embedding = materialize_clip_embeddings(&tables, &sidecar.clip_ids)?;
    let negative_embedding = if sidecar.negative_clip_ids.is_empty() {
        None
    } else {
        Some(materialize_clip_embeddings(
            &tables,
            &sidecar.negative_clip_ids,
        )?)
    };
    let encoder = FluxClipTextEncoder::load(knot_source, knot)?;
    let prompt_forward = encoder.forward(&prompt_embedding.values, &sidecar.clip_ids)?;
    let prompt_stats = summarize_f32s(&prompt_forward.pooled)?;
    let negative_forward = match negative_embedding.as_ref() {
        Some(embedding) => Some(encoder.forward(&embedding.values, &sidecar.negative_clip_ids)?),
        None => None,
    };
    let negative_hash = negative_forward
        .as_ref()
        .map(|forward| hash_f32s(&forward.pooled));
    let prompt_sensitive = negative_hash
        .map(|hash| hash != prompt_stats.hash)
        .unwrap_or(prompt_stats.hash != 0);
    if !prompt_sensitive {
        return Err("CLIP pooled output is not prompt-sensitive".to_string());
    }

    Ok(FluxClipForwardProbe {
        status: "ready".to_string(),
        detail: "native CLIP text encoder forward produced finite pooled conditioning".to_string(),
        pool_index: prompt_forward.pool_index,
        negative_pool_index: negative_forward.as_ref().map(|forward| forward.pool_index),
        pooled_values: prompt_stats.values,
        pooled_finite: prompt_stats.finite,
        pooled_mean: prompt_stats.mean,
        pooled_std: prompt_stats.std,
        pooled_rms: prompt_stats.rms,
        pooled_hash: prompt_stats.hash,
        negative_pooled_hash: negative_hash,
        prompt_sensitive,
        fetched_tensor_count: tables.fetched_tensors.len() + encoder.fetched_tensor_count,
    })
}

#[cfg(not(target_arch = "wasm32"))]
struct FluxDitBlock0SampleState {
    image_token_count: usize,
    image_token_dim: usize,
    prefix_len: usize,
    image_projection: Vec<f32>,
    text_projection: Vec<f32>,
    image_qkv: Vec<f32>,
    text_qkv: Vec<f32>,
    fetched_tensor_count: usize,
}

#[cfg(not(target_arch = "wasm32"))]
fn build_flux_dit_block0_sample_state(
    knot_source: &str,
    knot: &KnotWeights,
    options: &FluxTxt2ImgOptions,
    sidecar: &FluxTokenSidecar,
    clip_forward: &FluxClipForwardProbe,
    t5_forward: &FluxEmbeddingProbe,
    t5_prefix_output: Option<&[f32]>,
) -> Result<FluxDitBlock0SampleState, String> {
    if !clip_forward.is_ready() {
        return Err("CLIP forward must be ready before DiT block-0 boundary".to_string());
    }
    if !t5_forward.is_ready() {
        return Err("T5 exact-prefix forward must be ready before DiT block-0 boundary".to_string());
    }
    if !t5_forward.prompt_sensitive {
        return Err("T5 exact-prefix forward is not prompt-sensitive".to_string());
    }
    if sidecar.t5_ids.is_empty() {
        return Err("T5 token ids are missing from token sidecar".to_string());
    }
    if FLUX_DIT_HEADS * FLUX_DIT_HEAD_DIM != FLUX_DIT_HIDDEN_DIM {
        return Err(format!(
            "FLUX DiT head layout mismatch: heads={FLUX_DIT_HEADS} head_dim={FLUX_DIT_HEAD_DIM} hidden={FLUX_DIT_HIDDEN_DIM}"
        ));
    }
    let width = usize::try_from(options.width)
        .map_err(|_| "image width exceeds usize".to_string())?;
    let height = usize::try_from(options.height)
        .map_err(|_| "image height exceeds usize".to_string())?;
    if width % FLUX_VAE_SCALE_FACTOR != 0 || height % FLUX_VAE_SCALE_FACTOR != 0 {
        return Err(format!(
            "image dimensions must be divisible by FLUX VAE scale factor {FLUX_VAE_SCALE_FACTOR}"
        ));
    }

    let prefix_token_limit = validate_t5_prefix_tokens(options.t5_prefix_tokens)?;
    let prefix_len = sidecar.t5_ids.len().min(prefix_token_limit);
    if prefix_len == 0 {
        return Err("T5 prefix is empty after applying token limit".to_string());
    }
    let expected_t5_values = prefix_len * T5_HIDDEN_DIM;
    let t5_output = match t5_prefix_output {
        Some(values) if values.len() == expected_t5_values => values.to_vec(),
        Some(values) => {
            return Err(format!(
                "T5 prefix output length mismatch: expected {expected_t5_values}, got {}",
                values.len()
            ));
        }
        None => {
            let t5_embedding =
                materialize_t5_embeddings(knot_source, knot, &sidecar.t5_ids[..prefix_len])?;
            let t5_weights = load_t5_block0_prefix_weights(knot_source, knot, prefix_len)?;
            t5_exact_prefix_forward(
                &t5_embedding.values,
                &t5_weights,
                FluxT5PrefixConfig {
                    seq_len: prefix_len,
                    hidden_dim: T5_HIDDEN_DIM,
                    heads: T5_HEADS,
                    head_dim: T5_HEAD_DIM,
                    ff_dim: T5_FFN_DIM,
                    eps: T5_LAYER_NORM_EPS,
                },
            )?
        }
    };

    let latent_width = width / FLUX_VAE_SCALE_FACTOR;
    let latent_height = height / FLUX_VAE_SCALE_FACTOR;
    let carrier = load_flux_carrier_tensors(knot_source, knot)?;
    let carrier_hash = hash_carrier_tensors(&carrier);
    let conditioning = build_flux_carrier_conditioning(options, clip_forward, t5_forward, carrier_hash);
    let latents = seed_flux_carrier_latents(
        FLUX_LATENT_CHANNELS,
        latent_height,
        latent_width,
        options.seed,
        &conditioning,
    );
    let patch_spec = FluxLatentPatchSpec {
        channels: FLUX_LATENT_CHANNELS,
        height: latent_height,
        width: latent_width,
        patch: FLUX_DIT_PATCH,
    };
    let image_token_count = patch_spec.token_count()?;
    let image_token_dim = patch_spec.token_dim()?;
    let image_tokens = pack_flux_latents_to_tokens(&latents, patch_spec)?;
    let sampled_image_token = &image_tokens[..image_token_dim];

    let image_projection = project_q8_linear_with_bias(
        knot_source,
        knot,
        "flux_img_in_weight",
        "flux_img_in_bias",
        sampled_image_token,
        FLUX_DIT_HIDDEN_DIM,
        image_token_dim,
    )?;
    let txt_in_weight = fetch_q8_tensor(
        knot_source,
        knot,
        "flux_txt_in_weight",
        &[FLUX_DIT_HIDDEN_DIM, T5_HIDDEN_DIM],
    )?;
    let txt_in_bias = fetch_f32_tensor(
        knot_source,
        knot,
        "flux_txt_in_bias",
        &[FLUX_DIT_HIDDEN_DIM],
    )?;
    let mut text_projection = Vec::with_capacity(prefix_len * FLUX_DIT_HIDDEN_DIM);
    for token_index in 0..prefix_len {
        let start = token_index * T5_HIDDEN_DIM;
        let projected = apply_q8_linear_with_bias(
            "flux_txt_in_weight",
            "flux_txt_in_bias",
            &t5_output[start..start + T5_HIDDEN_DIM],
            &txt_in_weight,
            &txt_in_bias,
            FLUX_DIT_HIDDEN_DIM,
            T5_HIDDEN_DIM,
        )?;
        text_projection.extend_from_slice(&projected);
    }
    let (image_qkv, image_qkv_tensor_count) = project_flux_dit_qkv(
        knot_source,
        knot,
        "flux_dbl_0_img",
        &image_projection,
    )?;
    let text_qkv_projection = FluxDitQkvProjection::load(knot_source, knot, "flux_dbl_0_txt")?;
    let mut text_qkv = Vec::with_capacity(prefix_len * 3 * FLUX_DIT_HIDDEN_DIM);
    for token_index in 0..prefix_len {
        let start = token_index * FLUX_DIT_HIDDEN_DIM;
        let projected = text_qkv_projection.project(
            &text_projection[start..start + FLUX_DIT_HIDDEN_DIM],
        )?;
        text_qkv.extend_from_slice(&projected);
    }
    let text_qkv_tensor_count = text_qkv_projection.tensor_count();

    Ok(FluxDitBlock0SampleState {
        image_token_count,
        image_token_dim,
        prefix_len,
        image_projection,
        text_projection,
        image_qkv,
        text_qkv,
        fetched_tensor_count: FLUX_CARRIER_TENSORS.len()
            + t5_prefix_fetched_tensors().len()
            + 4
            + image_qkv_tensor_count
            + text_qkv_tensor_count,
    })
}

#[cfg(not(target_arch = "wasm32"))]
fn summarize_flux_dit_block0_boundary(
    state: &FluxDitBlock0SampleState,
) -> Result<FluxDitBoundaryProbe, String> {
    let mut boundary_values = Vec::with_capacity(
        state.image_projection.len()
            + state.text_projection.len()
            + state.image_qkv.len()
            + state.text_qkv.len(),
    );
    boundary_values.extend_from_slice(&state.image_projection);
    boundary_values.extend_from_slice(&state.text_projection);
    boundary_values.extend_from_slice(&state.image_qkv);
    boundary_values.extend_from_slice(&state.text_qkv);
    let stats = summarize_f32s(&boundary_values)?;

    Ok(FluxDitBoundaryProbe {
        status: "ready".to_string(),
        detail: format!(
            "native FLUX DiT block-0 boundary ready: img_in/txt_in plus image/text qkv over {} T5 prefix token(s)",
            state.prefix_len,
        ),
        image_token_count: state.image_token_count,
        image_token_dim: state.image_token_dim,
        sampled_image_tokens: 1,
        text_token_count: state.prefix_len,
        text_hidden_dim: T5_HIDDEN_DIM,
        stream_dim: FLUX_DIT_HIDDEN_DIM,
        values: stats.values,
        finite: stats.finite,
        mean: stats.mean,
        std: stats.std,
        rms: stats.rms,
        hash: stats.hash,
        image_projection_hash: hash_f32s(&state.image_projection),
        text_projection_hash: hash_f32s(&state.text_projection),
        block0_image_qkv_hash: hash_f32s(&state.image_qkv),
        block0_text_qkv_hash: hash_f32s(&state.text_qkv),
        fetched_tensor_count: state.fetched_tensor_count,
    })
}

