#[cfg(not(target_arch = "wasm32"))]
fn summarize_flux_dit_block0_attention(
    knot_source: &str,
    knot: &KnotWeights,
    state: &FluxDitBlock0SampleState,
) -> Result<FluxDitAttentionProbe, String> {
    let stream_tokens = state.prefix_len + 1;
    let stream_values = stream_tokens * FLUX_DIT_HIDDEN_DIM;
    let mut q = vec![0.0f32; stream_values];
    let mut k = vec![0.0f32; stream_values];
    let mut v = vec![0.0f32; stream_values];
    for token_index in 0..state.prefix_len {
        copy_flux_dit_qkv_token(
            &state.text_qkv,
            token_index,
            &mut q,
            &mut k,
            &mut v,
            token_index,
        )?;
    }
    copy_flux_dit_qkv_token(
        &state.image_qkv,
        0,
        &mut q,
        &mut k,
        &mut v,
        state.prefix_len,
    )?;

    let txt_q_norm = fetch_flux_dit_norm_scale(knot_source, knot, "flux_dbl_0_txt_q_norm")?;
    let txt_k_norm = fetch_flux_dit_norm_scale(knot_source, knot, "flux_dbl_0_txt_k_norm")?;
    let img_q_norm = fetch_flux_dit_norm_scale(knot_source, knot, "flux_dbl_0_img_q_norm")?;
    let img_k_norm = fetch_flux_dit_norm_scale(knot_source, knot, "flux_dbl_0_img_k_norm")?;
    for token_index in 0..state.prefix_len {
        let start = token_index * FLUX_DIT_HIDDEN_DIM;
        let end = start + FLUX_DIT_HIDDEN_DIM;
        rms_norm_per_head(
            &mut q[start..end],
            &txt_q_norm,
            FLUX_DIT_HEADS,
            FLUX_DIT_HEAD_DIM,
            FLUX_DIT_QK_NORM_EPS,
        );
        rms_norm_per_head(
            &mut k[start..end],
            &txt_k_norm,
            FLUX_DIT_HEADS,
            FLUX_DIT_HEAD_DIM,
            FLUX_DIT_QK_NORM_EPS,
        );
    }
    let image_start = state.prefix_len * FLUX_DIT_HIDDEN_DIM;
    let image_end = image_start + FLUX_DIT_HIDDEN_DIM;
    rms_norm_per_head(
        &mut q[image_start..image_end],
        &img_q_norm,
        FLUX_DIT_HEADS,
        FLUX_DIT_HEAD_DIM,
        FLUX_DIT_QK_NORM_EPS,
    );
    rms_norm_per_head(
        &mut k[image_start..image_end],
        &img_k_norm,
        FLUX_DIT_HEADS,
        FLUX_DIT_HEAD_DIM,
        FLUX_DIT_QK_NORM_EPS,
    );

    let attention = sampled_flux_dit_attention(&q, &k, &v, stream_tokens)?;
    let image_out = project_q8_linear_with_bias(
        knot_source,
        knot,
        "flux_dbl_0_img_out_weight",
        "flux_dbl_0_img_out_bias",
        &attention[image_start..image_end],
        FLUX_DIT_HIDDEN_DIM,
        FLUX_DIT_HIDDEN_DIM,
    )?;
    let text_out = project_q8_linear_with_bias(
        knot_source,
        knot,
        "flux_dbl_0_txt_out_weight",
        "flux_dbl_0_txt_out_bias",
        &attention[..FLUX_DIT_HIDDEN_DIM],
        FLUX_DIT_HIDDEN_DIM,
        FLUX_DIT_HIDDEN_DIM,
    )?;
    let mut values = Vec::with_capacity(attention.len() + image_out.len() + text_out.len());
    values.extend_from_slice(&attention);
    values.extend_from_slice(&image_out);
    values.extend_from_slice(&text_out);
    let stats = summarize_f32s(&values)?;

    Ok(FluxDitAttentionProbe {
        status: "ready".to_string(),
        detail: format!(
            "sampled native FLUX DiT block-0 attention ready: q/k norm, full attention over {} sampled token(s), and img/txt out projection",
            stream_tokens,
        ),
        sampled_stream_tokens: stream_tokens,
        text_token_count: state.prefix_len,
        image_token_count: 1,
        heads: FLUX_DIT_HEADS,
        head_dim: FLUX_DIT_HEAD_DIM,
        stream_dim: FLUX_DIT_HIDDEN_DIM,
        values: stats.values,
        finite: stats.finite,
        mean: stats.mean,
        std: stats.std,
        rms: stats.rms,
        hash: stats.hash,
        attention_hash: hash_f32s(&attention),
        image_out_hash: hash_f32s(&image_out),
        text_out_hash: hash_f32s(&text_out),
        fetched_tensor_count: state.fetched_tensor_count + 8,
    })
}

#[cfg(not(target_arch = "wasm32"))]
fn copy_flux_dit_qkv_token(
    source_qkv: &[f32],
    source_token_index: usize,
    q: &mut [f32],
    k: &mut [f32],
    v: &mut [f32],
    destination_token_index: usize,
) -> Result<(), String> {
    let source_base = source_token_index
        .checked_mul(3 * FLUX_DIT_HIDDEN_DIM)
        .ok_or_else(|| "DiT QKV source index overflow".to_string())?;
    let destination_base = destination_token_index
        .checked_mul(FLUX_DIT_HIDDEN_DIM)
        .ok_or_else(|| "DiT QKV destination index overflow".to_string())?;
    if source_base + 3 * FLUX_DIT_HIDDEN_DIM > source_qkv.len() {
        return Err(format!(
            "DiT QKV source token {source_token_index} exceeds qkv length {}",
            source_qkv.len()
        ));
    }
    if destination_base + FLUX_DIT_HIDDEN_DIM > q.len()
        || destination_base + FLUX_DIT_HIDDEN_DIM > k.len()
        || destination_base + FLUX_DIT_HIDDEN_DIM > v.len()
    {
        return Err(format!(
            "DiT QKV destination token {destination_token_index} exceeds stream length {}",
            q.len()
        ));
    }
    q[destination_base..destination_base + FLUX_DIT_HIDDEN_DIM]
        .copy_from_slice(&source_qkv[source_base..source_base + FLUX_DIT_HIDDEN_DIM]);
    k[destination_base..destination_base + FLUX_DIT_HIDDEN_DIM].copy_from_slice(
        &source_qkv[source_base + FLUX_DIT_HIDDEN_DIM..source_base + 2 * FLUX_DIT_HIDDEN_DIM],
    );
    v[destination_base..destination_base + FLUX_DIT_HIDDEN_DIM].copy_from_slice(
        &source_qkv[source_base + 2 * FLUX_DIT_HIDDEN_DIM
            ..source_base + 3 * FLUX_DIT_HIDDEN_DIM],
    );
    Ok(())
}

#[cfg(not(target_arch = "wasm32"))]
fn sampled_flux_dit_attention(
    q: &[f32],
    k: &[f32],
    v: &[f32],
    stream_tokens: usize,
) -> Result<Vec<f32>, String> {
    let expected_values = stream_tokens
        .checked_mul(FLUX_DIT_HIDDEN_DIM)
        .ok_or_else(|| "DiT attention stream length overflow".to_string())?;
    if q.len() != expected_values || k.len() != expected_values || v.len() != expected_values {
        return Err(format!(
            "DiT attention stream mismatch: expected {expected_values}, got q={} k={} v={}",
            q.len(),
            k.len(),
            v.len()
        ));
    }
    let mut output = vec![0.0f32; expected_values];
    let mut scores = vec![0.0f32; stream_tokens];
    let scale = 1.0 / (FLUX_DIT_HEAD_DIM as f32).sqrt();
    for target in 0..stream_tokens {
        for head in 0..FLUX_DIT_HEADS {
            let q_start = target * FLUX_DIT_HIDDEN_DIM + head * FLUX_DIT_HEAD_DIM;
            let q_head = &q[q_start..q_start + FLUX_DIT_HEAD_DIM];
            for source in 0..stream_tokens {
                let k_start = source * FLUX_DIT_HIDDEN_DIM + head * FLUX_DIT_HEAD_DIM;
                scores[source] =
                    dot_product(q_head, &k[k_start..k_start + FLUX_DIT_HEAD_DIM]) * scale;
            }
            softmax(&mut scores);
            let out_start = target * FLUX_DIT_HIDDEN_DIM + head * FLUX_DIT_HEAD_DIM;
            for source in 0..stream_tokens {
                let v_start = source * FLUX_DIT_HIDDEN_DIM + head * FLUX_DIT_HEAD_DIM;
                let weight = scores[source];
                for dim in 0..FLUX_DIT_HEAD_DIM {
                    output[out_start + dim] += weight * v[v_start + dim];
                }
            }
        }
    }
    if output.iter().any(|value| !value.is_finite()) {
        return Err("sampled DiT attention produced non-finite output".to_string());
    }
    Ok(output)
}

#[cfg(not(target_arch = "wasm32"))]
fn fetch_flux_dit_norm_scale(
    knot_source: &str,
    knot: &KnotWeights,
    base_name: &str,
) -> Result<Vec<f32>, String> {
    for suffix in ["scale", "weight"] {
        let name = format!("{base_name}_{suffix}");
        if knot.metadata.contains_key(&name) {
            return fetch_f32_tensor(knot_source, knot, &name, &[FLUX_DIT_HEAD_DIM]);
        }
    }
    Err(format!(
        "missing FLUX DiT q/k norm tensor for {base_name}; expected _scale or _weight"
    ))
}

#[cfg(not(target_arch = "wasm32"))]
pub fn build_flux_native_visible_image_probe(
    knot_source: &str,
    knot: &KnotWeights,
    options: &FluxTxt2ImgOptions,
    clip_forward: &FluxClipForwardProbe,
    t5_forward: &FluxEmbeddingProbe,
) -> Result<FluxNativeImageProbe, String> {
    if !clip_forward.is_ready() {
        return Err("CLIP forward must be ready before native image decode".to_string());
    }
    if !t5_forward.is_ready() {
        return Err("T5 exact-prefix forward must be ready before native image decode".to_string());
    }
    if !t5_forward.prompt_sensitive {
        return Err("T5 exact-prefix forward is not prompt-sensitive".to_string());
    }
    let width = usize::try_from(options.width)
        .map_err(|_| "image width exceeds usize".to_string())?;
    let height = usize::try_from(options.height)
        .map_err(|_| "image height exceeds usize".to_string())?;
    if width == 0 || height == 0 {
        return Err("image dimensions must be positive".to_string());
    }
    if width % FLUX_VAE_SCALE_FACTOR != 0 || height % FLUX_VAE_SCALE_FACTOR != 0 {
        return Err(format!(
            "image dimensions must be divisible by FLUX VAE scale factor {FLUX_VAE_SCALE_FACTOR}"
        ));
    }

    let latent_width = width / FLUX_VAE_SCALE_FACTOR;
    let latent_height = height / FLUX_VAE_SCALE_FACTOR;
    let carrier = load_flux_carrier_tensors(knot_source, knot)?;
    let carrier_hash = hash_carrier_tensors(&carrier);
    let conditioning = build_flux_carrier_conditioning(options, clip_forward, t5_forward, carrier_hash);
    let vae_decoder_detail = inspect_flux_vae_decoder_bridge(knot_source, knot)?;
    let mut latents = seed_flux_carrier_latents(
        FLUX_LATENT_CHANNELS,
        latent_height,
        latent_width,
        options.seed,
        &conditioning,
    );
    let mut last_velocity = vec![0.0f32; latents.len()];
    for step_index in 0..options.steps {
        let sigma = 1.0 - (step_index as f32 / options.steps as f32);
        let next_sigma = 1.0 - ((step_index + 1) as f32 / options.steps as f32);
        carrier_velocity(
            &mut last_velocity,
            &latents,
            FLUX_LATENT_CHANNELS,
            latent_height,
            latent_width,
            step_index,
            options.steps,
            sigma,
            &conditioning,
            &carrier,
        );
        let spectral_color = options
            .spectral_schedule
            .get(step_index % options.spectral_schedule.len())
            .copied()
            .unwrap_or(SpectralDenoiseColor::White);
        last_velocity = apply_spectral_step(
            &last_velocity,
            FLUX_LATENT_CHANNELS,
            latent_height,
            latent_width,
            spectral_color,
            options.spectral_strength,
            options.residual_quantizer,
            options.residual_quant_step,
            options.residual_stride,
        )?;
        let delta_sigma = next_sigma - sigma;
        for (latent, velocity) in latents.iter_mut().zip(last_velocity.iter()) {
            *latent += delta_sigma * *velocity;
            if !latent.is_finite() {
                return Err("native carrier latent update produced non-finite value".to_string());
            }
        }
    }

    let image = decode_flux_carrier_image(
        &latents,
        FLUX_LATENT_CHANNELS,
        latent_height,
        latent_width,
        width,
        height,
        &conditioning,
        &carrier,
    )?;
    let distinct_probe_pixels = count_distinct_probe_pixels(&image);
    if distinct_probe_pixels < 8 {
        return Err(format!(
            "native carrier image is too close to blank: distinct_probe_pixels={distinct_probe_pixels}"
        ));
    }
    let output_path = Path::new(&options.output_path);
    if let Some(parent) = output_path.parent() {
        if !parent.as_os_str().is_empty() {
            std::fs::create_dir_all(parent)
                .map_err(|error| format!("create {}: {error}", parent.display()))?;
        }
    }
    image
        .save(output_path)
        .map_err(|error| format!("write {}: {error}", output_path.display()))?;
    let velocity_stats = summarize_f32s(&last_velocity)?;
    let rgba_hash = hash_bytes(image.as_raw());

    Ok(FluxNativeImageProbe {
        status: "ready".to_string(),
        detail: format!(
            "native T5-prefix-conditioned FLUX carrier wrote a finite nonblank PNG; {vae_decoder_detail}"
        ),
        conditioning_mode: "clip-forward-plus-t5-prefix-forward".to_string(),
        decode_mode: "native-rectified-flow-unsound-carrier".to_string(),
        vae_decoder_detail,
        output_path: options.output_path.clone(),
        width: options.width,
        height: options.height,
        latent_channels: FLUX_LATENT_CHANNELS,
        latent_height,
        latent_width,
        steps: options.steps,
        velocity_values: velocity_stats.values,
        velocity_finite: velocity_stats.finite,
        velocity_mean: velocity_stats.mean,
        velocity_std: velocity_stats.std,
        velocity_rms: velocity_stats.rms,
        velocity_hash: velocity_stats.hash,
        latent_hash: hash_f32s(&latents),
        rgba_hash,
        distinct_probe_pixels,
        carrier_tensor_hash: carrier_hash,
        carrier_tensors: carrier.iter().map(|tensor| tensor.report.clone()).collect(),
    })
}

/// Result of the real (non-carrier) FLUX diffusion pipeline.
#[cfg(not(target_arch = "wasm32"))]
#[derive(Debug, Clone)]
pub struct FluxRealImageResult {
    pub output_path: String,
    pub width: usize,
    pub height: usize,
    pub steps: usize,
    pub velocity_std: f32,
    pub velocity_hash: u64,
    pub latent_std: f32,
    pub luma_std: f32,
    pub distinct_pixels: usize,
    pub rgba_hash: u64,
    /// Whether the gated speculative (basin-gate) denoise path was active.
    pub gated: bool,
    /// Steps run at cheap-draft cost (admitted by the basin gate).
    pub gate_admitted: usize,
    /// Steps that missed and recomputed the exact velocity.
    pub gate_missed: usize,
    /// Admit rate (speedup proxy) over the denoise trajectory.
    pub gate_admit_rate: f64,
    /// Accumulated admitted displacement error (must be ≤ basin radius).
    pub gate_accumulated: f64,
    /// Remaining basin headroom at the end of the trajectory.
    pub gate_headroom: f64,
    /// Configured basin radius (the certified displacement budget).
    pub gate_basin_radius: f64,
    /// E_8 vs scalar residual energy on a real FLUX weight tile slab.
    pub e8_scalar_energy: f64,
    pub e8_lattice_energy: f64,
    /// Leech vs scalar residual energy on the same real FLUX weight slab.
    pub leech_scalar_energy: f64,
    pub leech_lattice_energy: f64,
}

/// Run the REAL FLUX schnell diffusion pipeline end to end:
/// T5+CLIP conditioning -> seeded Gaussian latents -> MMDiT velocity over a
/// flow-match Euler schedule -> AutoencoderKL decode -> PNG. This replaces the
/// procedural carrier painter for prompt-faithful image generation.
#[cfg(not(target_arch = "wasm32"))]
/// Cache key for a T5 full-stack forward: knot path + T5 token ids.
#[cfg(not(target_arch = "wasm32"))]
fn t5_cache_path(knot_source: &str, sidecar: &FluxTokenSidecar) -> std::path::PathBuf {
    let mut hasher = std::collections::hash_map::DefaultHasher::new();
    knot_source.hash(&mut hasher);
    sidecar.t5_ids.hash(&mut hasher);
    let key = hasher.finish();
    let dir = std::env::var("FLUX_T5_CACHE_DIR")
        .unwrap_or_else(|_| "/tmp/flux-phase1/t5-cache".to_string());
    std::path::Path::new(&dir).join(format!("t5-{key:016x}.f32bin"))
}

/// Load a cached T5 full-stack output, or None on any miss/error.
#[cfg(not(target_arch = "wasm32"))]
fn load_cached_t5_output(knot_source: &str, sidecar: &FluxTokenSidecar) -> Option<Vec<f32>> {
    if std::env::var("FLUX_T5_CACHE_DISABLE").is_ok() {
        return None;
    }
    let path = t5_cache_path(knot_source, sidecar);
    let bytes = std::fs::read(&path).ok()?;
    if bytes.is_empty() || bytes.len() % 4 != 0 {
        return None;
    }
    let mut out = vec![0.0f32; bytes.len() / 4];
    for (dst, chunk) in out.iter_mut().zip(bytes.chunks_exact(4)) {
        *dst = f32::from_le_bytes([chunk[0], chunk[1], chunk[2], chunk[3]]);
    }
    if out.iter().any(|v| !v.is_finite()) {
        return None;
    }
    Some(out)
}

/// Persist a T5 full-stack output to the disk cache (best-effort).
#[cfg(not(target_arch = "wasm32"))]
fn store_cached_t5_output(knot_source: &str, sidecar: &FluxTokenSidecar, out: &[f32]) {
    if std::env::var("FLUX_T5_CACHE_DISABLE").is_ok() {
        return;
    }
    let path = t5_cache_path(knot_source, sidecar);
    if let Some(parent) = path.parent() {
        let _ = std::fs::create_dir_all(parent);
    }
    let mut bytes = Vec::with_capacity(out.len() * 4);
    for v in out {
        bytes.extend_from_slice(&v.to_le_bytes());
    }
    if std::fs::write(&path, &bytes).is_ok() {
        eprintln!("[flux-real] T5 cache stored at {}", path.display());
    }
}

pub fn build_flux_real_image(
    knot_source: &str,
    knot: &KnotWeights,
    options: &FluxTxt2ImgOptions,
    sidecar: &FluxTokenSidecar,
) -> Result<FluxRealImageResult, String> {
    use crate::model_flux_mmdit::{
        flux_schnell_sigmas, FluxDit, FluxVae, FLUX_IN_CHANNELS, FLUX_LATENT_CHANNELS as MM_CH,
    };

    let width = usize::try_from(options.width).map_err(|_| "width exceeds usize".to_string())?;
    let height = usize::try_from(options.height).map_err(|_| "height exceeds usize".to_string())?;
    if width % FLUX_VAE_SCALE_FACTOR != 0 || height % FLUX_VAE_SCALE_FACTOR != 0 {
        return Err(format!(
            "image dimensions must be divisible by FLUX VAE scale factor {FLUX_VAE_SCALE_FACTOR}"
        ));
    }
    let latent_w = width / FLUX_VAE_SCALE_FACTOR; // pixels/8
    let latent_h = height / FLUX_VAE_SCALE_FACTOR;
    // patchified grid is latent/2
    let grid_h = latent_h / FLUX_DIT_PATCH;
    let grid_w = latent_w / FLUX_DIT_PATCH;
    if grid_h == 0 || grid_w == 0 {
        return Err("image too small for FLUX 2x2 patchify".to_string());
    }

    // ── conditioning ──
    if sidecar.t5_ids.is_empty() {
        return Err("T5 token ids missing".to_string());
    }
    let t0 = std::time::Instant::now();
    // T5 full-stack forward is the render bottleneck (~27 min CPU). Cache the
    // resulting hidden states to disk keyed by (knot path + T5 token ids) and
    // reload on a repeat render so single-stream/VAE iteration is fast.
    let txt = match load_cached_t5_output(knot_source, sidecar) {
        Some(cached) => {
            eprintln!(
                "[flux-real] T5 full stack CACHE HIT ({} f32) in {:?}",
                cached.len(),
                t0.elapsed()
            );
            cached
        }
        None => {
            let t5_state = build_flux_t5_full_stack_forward_state(knot_source, knot, sidecar)?;
            let out = t5_state.prompt_output; // [t5_len * 4096]
            eprintln!("[flux-real] T5 full stack done in {:?}", t0.elapsed());
            store_cached_t5_output(knot_source, sidecar, &out);
            out
        }
    };

    let clip_tables = load_clip_embedding_tables(knot_source, knot)?;
    let clip_ids = if sidecar.clip_ids.is_empty() {
        vec![CLIP_EOS_TOKEN_ID]
    } else {
        sidecar.clip_ids.clone()
    };
    let clip_emb = materialize_clip_embeddings(&clip_tables, &clip_ids)?;
    let clip_encoder = FluxClipTextEncoder::load(knot_source, knot)?;
    let clip_forward = clip_encoder.forward(&clip_emb.values, &clip_ids)?;
    let pooled = clip_forward.pooled; // [768]

    eprintln!("[flux-real] CLIP done");
    // ── load DiT + VAE ──
    let tl = std::time::Instant::now();
    let dit = FluxDit::load(knot_source, knot)?;
    eprintln!("[flux-real] DiT loaded in {:?}", tl.elapsed());
    let tv = std::time::Instant::now();
    let vae = FluxVae::load(knot_source, knot)?;
    eprintln!("[flux-real] VAE loaded in {:?}", tv.elapsed());
    gap_marker("after VAE load");
    #[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
    crate::cuda_matmul::log_vram("after VAE load");

    // ── seed Gaussian latents in packed token space [grid*grid, 64] ──
    let img_len = grid_h * grid_w;
    let mut rng = options.seed ^ 0x9E37_79B9_7F4A_7C15;
    let mut img_tokens = vec![0.0f32; img_len * FLUX_IN_CHANNELS];
    for v in img_tokens.iter_mut() {
        *v = gaussian(&mut rng);
    }
    gap_marker("after gaussian latent seed");

    // ── speculative-precision (basin-gate) denoise configuration ──
    // The Unsound-FLUX gate, now wired to the REAL velocity. When `gated`, each
    // step (after the first) drafts a CHEAP velocity (carry-forward of the prior
    // step's exact velocity — the standard flow speculative step) and admits it
    // only if the accumulated latent displacement error stays inside the basin
    // radius (`RealVelocityGate`/`BasinGate`, the runtime twin of
    // `net_displacement_within_basin`); otherwise it MISSES and carries the exact
    // velocity ("miss, not lie"). Off by env default → identical to the exact run.
    let gated = std::env::var("FLUX_GATED")
        .map(|v| v != "0" && !v.eq_ignore_ascii_case("false"))
        .unwrap_or(false);
    // Basin radius: certified displacement budget. Default scales with the
    // schedule's total exact displacement so it is meaningful at any step count;
    // overridable for sweeps. (A tighter radius ⇒ fewer admits, never a lie.)
    let basin_radius = std::env::var("FLUX_BASIN_RADIUS")
        .ok()
        .and_then(|v| v.parse::<f64>().ok());

    // ── E_8 / Leech vs scalar residual energy on a REAL FLUX weight tile ──
    // Measure the "superior at the same bit budget" claim on actual FLUX-schnell
    // weights (the final-layer projection's Q8_0 slab), once, before denoising.
    let (mut e8_scalar_energy, mut e8_lattice_energy) = (0.0f64, 0.0f64);
    let (mut leech_scalar_energy, mut leech_lattice_energy) = (0.0f64, 0.0f64);
    // The E8/Leech lattice-residual probe is a DIAGNOSTIC measurement on a real
    // FLUX weight tile (`flux_dbl_0_img_fc1_weight`, 12288×3072 = 37.7M f32). Its
    // Leech path runs ~1.57M single-threaded 24-D nearest-point decodes — minutes
    // of CPU that happen AFTER "VAE loaded" and BEFORE the denoise, producing the
    // exact "silent for 10+ min after DiT loaded" stall (NOT a DiT-gemm hang —
    // the denoise had not started yet). It is irrelevant to the rendered image,
    // so it is OFF by default; set FLUX_LATTICE_PROBE=1 to re-enable the report.
    let lattice_probe_enabled = std::env::var("FLUX_LATTICE_PROBE")
        .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
        .unwrap_or(false);
    if lattice_probe_enabled {
      if let Some(info) = knot.metadata.get(FLUX_LATTICE_PROBE_TENSOR) {
        if info.tensor_type.eq_ignore_ascii_case("Q8_0") {
            if let Ok(t) = fetch_knot_tensor_bytes_from_metadata(
                knot_source,
                &knot.metadata,
                knot.payload_offset,
                FLUX_LATTICE_PROBE_TENSOR,
            ) {
                let total = info
                    .shape
                    .as_ref()
                    .map(|s| s.iter().product::<usize>())
                    .unwrap_or((t.bytes.len() / 34) * 32);
                let rep =
                    crate::flux_lattice_residual::measure_flux_q8_tile_lattice(&t.bytes, total);
                e8_scalar_energy = rep.scalar_e8_energy;
                e8_lattice_energy = rep.e8_energy;
                leech_scalar_energy = rep.scalar_leech_energy;
                leech_lattice_energy = rep.leech_energy;
                eprintln!(
                    "[flux-real] lattice residual on {} ({} E8 tiles, {} Leech tiles):\n  \
                     E8:    scalar {:.6e}  lattice {:.6e}  ({:+.1}% energy)\n  \
                     Leech: scalar {:.6e}  lattice {:.6e}  ({:+.1}% energy)",
                    FLUX_LATTICE_PROBE_TENSOR,
                    rep.e8_tiles,
                    rep.leech_tiles,
                    e8_scalar_energy,
                    e8_lattice_energy,
                    -100.0 * rep.e8_reduction(),
                    leech_scalar_energy,
                    leech_lattice_energy,
                    -100.0 * rep.leech_reduction(),
                );
            }
        }
      }
    }

    gap_marker("before flux_schnell_sigmas");
    // ── flow-match Euler (optionally basin-gated) ──
    let sigmas = flux_schnell_sigmas(options.steps, img_len);
    gap_marker("after flux_schnell_sigmas");
    let mut last_velocity_std = 0.0f32;
    let mut last_velocity_hash = 0u64;
    let mut prev_velocity: Option<Vec<f32>> = None;
    // Default basin radius: a small fraction of the typical per-step displacement
    // (‖v‖≈1, dt≈1/steps ⇒ disp≈1/steps), summed conservatively. We size it so a
    // few near-identical steps admit but a divergent step misses.
    let default_radius = 0.15f64;
    let mut vgate = crate::basin_gate::RealVelocityGate::new(basin_radius.unwrap_or(default_radius));
    // ── GPU DiT-phase boundary ──
    // T5's resident f32 weights are no longer needed; free them so the ~24 GB L4
    // is almost entirely available for the DiT working set, and reset the
    // per-phase instrumentation so the DiT's first uploads/gemms log (the global
    // "first 8" heuristic is already past 8 from T5). Without freeing T5 + a
    // budgeted DiT cache, the DiT's ~47 GB f32 working set OOMed VRAM mid-block
    // and the render silently hung (the v4 "DiT hang"). No-op without `--features
    // cuda` / a GPU.
    gap_marker("before begin_dit_phase");
    #[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
    {
        crate::cuda_matmul::begin_dit_phase();
        crate::cuda_matmul::log_vram("after begin_dit_phase");
    }
    gap_marker("after begin_dit_phase");
    eprintln!(
        "[flux-real] DiT denoise begin: {} step(s), {} img tokens + {} txt tokens",
        options.steps,
        img_len,
        txt.len() / crate::model_flux_mmdit::FLUX_TXT_DIM
    );
    let denoise_started = std::time::Instant::now();
    for step in 0..options.steps {
        let sigma = sigmas[step];
        let sigma_next = sigmas[step + 1];
        let dt = sigma_next - sigma;
        let ts = std::time::Instant::now();
        if step == 0 {
            gap_marker("before dit.velocity step 0");
            #[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
            crate::cuda_matmul::log_vram("before dit.velocity step 0");
        }
        // Exact velocity is always computed here so the gate has ground truth and
        // the gated-vs-exact render error is measurable within the margin. The
        // admit rate is the speedup PROXY: an admitted step is one a production
        // path could have skipped (carry-forward) without leaving the basin.
        let velocity = dit.velocity(&img_tokens, &txt, &pooled, sigma, grid_h, grid_w)?;
        eprintln!("[flux-real] step {step} velocity in {:?}", ts.elapsed());

        let used: Vec<f32> = if gated {
            match prev_velocity.as_ref() {
                None => {
                    // Step 0: no draft available — take exact (a forced miss).
                    velocity.clone()
                }
                Some(prev) => {
                    let cheap = prev; // carry-forward draft
                    let decision = vgate.offer_step(dt, &velocity, cheap);
                    // Observational: per-step displacement residual the cheap
                    // (carry-forward) draft would inject — used to size a
                    // principled basin radius from the OBSERVED schedule.
                    eprintln!(
                        "[flux-real] gate step {step}: dt={:.6} residual={:.6} admitted={}",
                        dt,
                        decision.residual(),
                        decision.admitted()
                    );
                    if decision.admitted() {
                        cheap.clone()
                    } else {
                        velocity.clone()
                    }
                }
            }
        } else {
            velocity.clone()
        };
        prev_velocity = Some(velocity.clone());

        let vstats = summarize_f32s(&velocity)?;
        last_velocity_std = vstats.std;
        last_velocity_hash = vstats.hash;
        for (x, vv) in img_tokens.iter_mut().zip(used.iter()) {
            *x += dt * *vv;
            if !x.is_finite() {
                return Err(format!("latent went non-finite at step {step}"));
            }
        }
    }
    eprintln!(
        "[flux-real] DiT denoise DONE: {} step(s) in {:?}",
        options.steps,
        denoise_started.elapsed()
    );
    let gate_rep = vgate.report();
    if gated {
        eprintln!(
            "[flux-real] BASIN GATE: admitted {}/{} ({:.1}%)  missed {}  \
             accumulated {:.6} / radius {:.6} (headroom {:.6})  within_basin={}",
            gate_rep.admitted,
            gate_rep.steps,
            100.0 * gate_rep.admit_rate,
            gate_rep.missed,
            gate_rep.accumulated,
            gate_rep.basin_radius,
            gate_rep.headroom,
            gate_rep.within_basin(),
        );
    }
    let latent_stats = summarize_f32s(&img_tokens)?;

    // ── op-level per-tile speculative-dequant admit rate (real render) ──
    // If FLUX_SPEC_DEQUANT was active, block-0 img_fc1 ran through the per-tile
    // gated matmul; report the admit rate accumulated over the whole render.
    {
        let cfg = crate::flux_spec_dequant::spec_runtime_config();
        if cfg.enabled {
            let (admitted, tiles, rate) = crate::flux_spec_dequant::render_spec_admit_rate();
            eprintln!(
                "[flux-real] OP-LEVEL spec-dequant ({}, γ={:.3}): {} / {} tiles admitted coarse \
                 = {:.2}% admit rate over the render",
                cfg.lattice.name(),
                cfg.gamma,
                admitted,
                tiles,
                100.0 * rate
            );
        }
    }

    // ── unpatchify tokens [grid*grid,64] -> latents [16, latent_h, latent_w] ──
    let latents = unpatchify_flux_tokens(&img_tokens, MM_CH, grid_h, grid_w);

    // ── VAE decode ──
    let rgb = vae.decode(&latents, latent_h, latent_w)?; // [h*w*3] interleaved
    let out_h = latent_h * FLUX_VAE_SCALE_FACTOR;
    let out_w = latent_w * FLUX_VAE_SCALE_FACTOR;

    // luma std + distinct pixels
    let mut luma = Vec::with_capacity(out_h * out_w);
    for p in 0..out_h * out_w {
        let r = rgb[p * 3] as f32;
        let g = rgb[p * 3 + 1] as f32;
        let b = rgb[p * 3 + 2] as f32;
        luma.push(0.299 * r + 0.587 * g + 0.114 * b);
    }
    let lmean = luma.iter().sum::<f32>() / luma.len() as f32;
    let luma_std =
        (luma.iter().map(|x| (x - lmean) * (x - lmean)).sum::<f32>() / luma.len() as f32).sqrt();
    let mut distinct = std::collections::HashSet::new();
    for p in 0..out_h * out_w {
        distinct.insert((rgb[p * 3], rgb[p * 3 + 1], rgb[p * 3 + 2]));
    }

    // write PNG
    let mut image = RgbaImage::new(out_w as u32, out_h as u32);
    for y in 0..out_h {
        for x in 0..out_w {
            let p = y * out_w + x;
            image.put_pixel(
                x as u32,
                y as u32,
                Rgba([rgb[p * 3], rgb[p * 3 + 1], rgb[p * 3 + 2], 255]),
            );
        }
    }
    let output_path = Path::new(&options.output_path);
    if let Some(parent) = output_path.parent() {
        if !parent.as_os_str().is_empty() {
            std::fs::create_dir_all(parent)
                .map_err(|e| format!("create {}: {e}", parent.display()))?;
        }
    }
    image
        .save(output_path)
        .map_err(|e| format!("write {}: {e}", output_path.display()))?;
    let rgba_hash = hash_bytes(image.as_raw());

    Ok(FluxRealImageResult {
        output_path: options.output_path.clone(),
        width: out_w,
        height: out_h,
        steps: options.steps,
        velocity_std: last_velocity_std,
        velocity_hash: last_velocity_hash,
        latent_std: latent_stats.std,
        luma_std,
        distinct_pixels: distinct.len(),
        rgba_hash,
        gated,
        gate_admitted: gate_rep.admitted,
        gate_missed: gate_rep.missed,
        gate_admit_rate: gate_rep.admit_rate,
        gate_accumulated: gate_rep.accumulated,
        gate_headroom: gate_rep.headroom,
        gate_basin_radius: gate_rep.basin_radius,
        e8_scalar_energy,
        e8_lattice_energy,
        leech_scalar_energy,
        leech_lattice_energy,
    })
}

/// Box-Muller Gaussian from an xorshift stream.
#[cfg(not(target_arch = "wasm32"))]
fn gaussian(state: &mut u64) -> f32 {
    let u1 = next_unit(state).max(1e-7);
    let u2 = next_unit(state);
    let r = (-2.0 * u1.ln()).sqrt();
    r * (std::f32::consts::TAU * u2).cos()
}

#[cfg(not(target_arch = "wasm32"))]
fn next_unit(state: &mut u64) -> f32 {
    *state = xorshift64(*state);
    ((*state >> 11) as f64 / (1u64 << 53) as f64) as f32
}

/// Inverse of pack_flux_latents_to_tokens for the packed [grid*grid, c*2*2]
/// token layout. tokens[t] holds channel-major 2x2 patches.
#[cfg(not(target_arch = "wasm32"))]
fn unpatchify_flux_tokens(tokens: &[f32], channels: usize, grid_h: usize, grid_w: usize) -> Vec<f32> {
    let patch = FLUX_DIT_PATCH;
    let lat_h = grid_h * patch;
    let lat_w = grid_w * patch;
    let token_dim = channels * patch * patch;
    let mut latents = vec![0.0f32; channels * lat_h * lat_w];
    for py in 0..grid_h {
        for px in 0..grid_w {
            let token_base = (py * grid_w + px) * token_dim;
            for ch in 0..channels {
                for dy in 0..patch {
                    for dx in 0..patch {
                        let ti = token_base + (ch * patch + dy) * patch + dx;
                        let li =
                            ch * lat_h * lat_w + (py * patch + dy) * lat_w + (px * patch + dx);
                        latents[li] = tokens[ti];
                    }
                }
            }
        }
    }
    latents
}

#[cfg(not(target_arch = "wasm32"))]
fn inspect_flux_vae_decoder_bridge(
    knot_source: &str,
    knot: &KnotWeights,
) -> Result<String, String> {
    let conv_in = fetch_knot_tensor_bytes_from_metadata(
        knot_source,
        &knot.metadata,
        knot.payload_offset,
        "flux_vae_decoder_conv_in_weight",
    )
    .map_err(|error| format!("fetch flux_vae_decoder_conv_in_weight: {error}"))?;
    let conv_out = fetch_knot_tensor_bytes_from_metadata(
        knot_source,
        &knot.metadata,
        knot.payload_offset,
        "flux_vae_decoder_conv_out_weight",
    )
    .map_err(|error| format!("fetch flux_vae_decoder_conv_out_weight: {error}"))?;

    let conv_in_shape = conv_in
        .info
        .shape
        .as_ref()
        .ok_or_else(|| "flux_vae_decoder_conv_in_weight is missing shape metadata".to_string())?;
    let conv_out_shape = conv_out.info.shape.as_ref().ok_or_else(|| {
        "flux_vae_decoder_conv_out_weight is missing shape metadata".to_string()
    })?;
    if conv_in_shape.len() != 4 || conv_out_shape.len() != 4 {
        return Ok(format!(
            "exact VAE decoder bridge is not ready: conv_in={:?} conv_out={:?}; expected 4D decoder tensors",
            conv_in_shape, conv_out_shape
        ));
    }

    let conv_in_input_channels = conv_in_shape[1];
    let conv_in_output_channels = conv_in_shape[0];
    let conv_in_kernel = conv_in_shape[2];
    let conv_out_input_channels = conv_out_shape[1];
    let conv_out_output_channels = conv_out_shape[0];
    let conv_out_kernel = conv_out_shape[2];

    if conv_in_kernel != 3 || conv_out_kernel != 3 {
        return Ok(format!(
            "exact VAE decoder bridge is not ready: conv_in={:?} conv_out={:?}; expected 3x3 kernels for the decoder boundary",
            conv_in_shape, conv_out_shape
        ));
    }

    if conv_out_input_channels == FLUX_LATENT_CHANNELS {
        return Ok(format!(
            "exact VAE decoder bridge is ready: conv_in={:?} conv_out={:?}; current {FLUX_LATENT_CHANNELS}-channel latents can enter the VAE decode boundary",
            conv_in_shape, conv_out_shape
        ));
    }

    Ok(format!(
        "exact VAE decoder bridge is blocked: conv_in={:?} maps {} input channel(s) to {} output channel(s), while conv_out={:?} maps {} input channel(s) to {} RGB output channel(s); current carrier latents are {}-channel, so the real VAE decode still needs the missing intermediate decoder state",
        conv_in_shape,
        conv_in_input_channels,
        conv_in_output_channels,
        conv_out_shape,
        conv_out_input_channels,
        conv_out_output_channels,
        FLUX_LATENT_CHANNELS
    ))
}

