#[cfg(not(target_arch = "wasm32"))]
fn load_clip_embedding_tables(
    knot_source: &str,
    knot: &KnotWeights,
) -> Result<ClipEmbeddingTables, String> {
    let token_tensor = fetch_knot_tensor_bytes_from_metadata(
        knot_source,
        &knot.metadata,
        knot.payload_offset,
        CLIP_TOKEN_EMBEDDING,
    )
    .map_err(|error| format!("fetch CLIP token embedding: {error}"))?;
    let position_tensor = fetch_knot_tensor_bytes_from_metadata(
        knot_source,
        &knot.metadata,
        knot.payload_offset,
        CLIP_POSITION_EMBEDDING,
    )
    .map_err(|error| format!("fetch CLIP position embedding: {error}"))?;
    if !token_tensor.info.tensor_type.eq_ignore_ascii_case("Q8_0") {
        return Err(format!(
            "{CLIP_TOKEN_EMBEDDING} must be Q8_0, got {}",
            token_tensor.info.tensor_type
        ));
    }
    if !position_tensor.info.tensor_type.eq_ignore_ascii_case("F32")
        && !position_tensor.info.tensor_type.eq_ignore_ascii_case("fp32")
    {
        return Err(format!(
            "{CLIP_POSITION_EMBEDDING} must be F32, got {}",
            position_tensor.info.tensor_type
        ));
    }
    let token_shape = expect_shape(&token_tensor.info.shape, CLIP_TOKEN_EMBEDDING, 2)?;
    let position_shape = expect_shape(&position_tensor.info.shape, CLIP_POSITION_EMBEDDING, 2)?;
    let vocab_size = token_shape[0];
    let hidden_dim = token_shape[1];
    if hidden_dim != CLIP_HIDDEN_DIM {
        return Err(format!(
            "{CLIP_TOKEN_EMBEDDING} hidden dim mismatch: expected {CLIP_HIDDEN_DIM}, got {hidden_dim}"
        ));
    }
    if position_shape[1] != hidden_dim {
        return Err(format!(
            "CLIP token/position hidden dims differ: {} vs {}",
            hidden_dim, position_shape[1]
        ));
    }
    let position_values =
        parse_f32_le_tensor(&position_tensor.bytes, position_shape[0] * position_shape[1])?;
    Ok(ClipEmbeddingTables {
        token_bytes: token_tensor.bytes,
        vocab_size,
        hidden_dim,
        position_values,
        position_tokens: position_shape[0],
        fetched_tensors: vec![token_tensor.name, position_tensor.name],
    })
}

#[cfg(not(target_arch = "wasm32"))]
fn materialize_clip_embeddings(
    tables: &ClipEmbeddingTables,
    clip_ids: &[i64],
) -> Result<ClipEmbeddingState, String> {
    if clip_ids.is_empty() {
        return Err("CLIP token ids are missing".to_string());
    }
    if clip_ids.len() > tables.position_tokens {
        return Err(format!(
            "CLIP sidecar token count {} exceeds position table length {}",
            clip_ids.len(),
            tables.position_tokens
        ));
    }
    let mut values = vec![0.0f32; clip_ids.len() * tables.hidden_dim];
    let mut token_row = vec![0.0f32; tables.hidden_dim];
    for (position, token_id) in clip_ids.iter().enumerate() {
        if *token_id < 0 {
            return Err(format!("CLIP token id at position {position} is negative"));
        }
        let token_id = usize::try_from(*token_id)
            .map_err(|_| format!("CLIP token id at position {position} exceeds usize"))?;
        if token_id >= tables.vocab_size {
            return Err(format!(
                "CLIP token id {token_id} at position {position} exceeds vocab size {}",
                tables.vocab_size
            ));
        }
        dequantize_q8_0_row(
            &mut token_row,
            &tables.token_bytes,
            token_id,
            tables.hidden_dim,
        );
        let offset = position * tables.hidden_dim;
        for hidden in 0..tables.hidden_dim {
            values[offset + hidden] = token_row[hidden] + tables.position_values[offset + hidden];
        }
    }
    let stats = summarize_f32s(&values)?;
    if stats.values != clip_ids.len() * tables.hidden_dim {
        return Err("CLIP embedding materialization produced wrong value count".to_string());
    }
    Ok(ClipEmbeddingState { values })
}

#[cfg(not(target_arch = "wasm32"))]
impl FluxClipTextEncoder {
    fn load(knot_source: &str, knot: &KnotWeights) -> Result<Self, String> {
        let mut layers = Vec::with_capacity(CLIP_LAYERS);
        let mut fetched_tensor_count = 0usize;
        for layer in 0..CLIP_LAYERS {
            let prefix = format!("flux_clip_text_model_encoder_layers_{layer}");
            layers.push(FluxClipLayerWeights {
                layer_norm1_weight: fetch_f32_tensor(
                    knot_source,
                    knot,
                    &format!("{prefix}_layer_norm1_weight"),
                    &[CLIP_HIDDEN_DIM],
                )?,
                layer_norm1_bias: fetch_f32_tensor(
                    knot_source,
                    knot,
                    &format!("{prefix}_layer_norm1_bias"),
                    &[CLIP_HIDDEN_DIM],
                )?,
                layer_norm2_weight: fetch_f32_tensor(
                    knot_source,
                    knot,
                    &format!("{prefix}_layer_norm2_weight"),
                    &[CLIP_HIDDEN_DIM],
                )?,
                layer_norm2_bias: fetch_f32_tensor(
                    knot_source,
                    knot,
                    &format!("{prefix}_layer_norm2_bias"),
                    &[CLIP_HIDDEN_DIM],
                )?,
                q_proj_weight: fetch_q8_tensor(
                    knot_source,
                    knot,
                    &format!("{prefix}_self_attn_q_proj_weight"),
                    &[CLIP_HIDDEN_DIM, CLIP_HIDDEN_DIM],
                )?,
                q_proj_bias: fetch_f32_tensor(
                    knot_source,
                    knot,
                    &format!("{prefix}_self_attn_q_proj_bias"),
                    &[CLIP_HIDDEN_DIM],
                )?,
                k_proj_weight: fetch_q8_tensor(
                    knot_source,
                    knot,
                    &format!("{prefix}_self_attn_k_proj_weight"),
                    &[CLIP_HIDDEN_DIM, CLIP_HIDDEN_DIM],
                )?,
                k_proj_bias: fetch_f32_tensor(
                    knot_source,
                    knot,
                    &format!("{prefix}_self_attn_k_proj_bias"),
                    &[CLIP_HIDDEN_DIM],
                )?,
                v_proj_weight: fetch_q8_tensor(
                    knot_source,
                    knot,
                    &format!("{prefix}_self_attn_v_proj_weight"),
                    &[CLIP_HIDDEN_DIM, CLIP_HIDDEN_DIM],
                )?,
                v_proj_bias: fetch_f32_tensor(
                    knot_source,
                    knot,
                    &format!("{prefix}_self_attn_v_proj_bias"),
                    &[CLIP_HIDDEN_DIM],
                )?,
                out_proj_weight: fetch_q8_tensor(
                    knot_source,
                    knot,
                    &format!("{prefix}_self_attn_out_proj_weight"),
                    &[CLIP_HIDDEN_DIM, CLIP_HIDDEN_DIM],
                )?,
                out_proj_bias: fetch_f32_tensor(
                    knot_source,
                    knot,
                    &format!("{prefix}_self_attn_out_proj_bias"),
                    &[CLIP_HIDDEN_DIM],
                )?,
                fc1_weight: fetch_q8_tensor(
                    knot_source,
                    knot,
                    &format!("{prefix}_mlp_fc1_weight"),
                    &[CLIP_INTERMEDIATE_DIM, CLIP_HIDDEN_DIM],
                )?,
                fc1_bias: fetch_f32_tensor(
                    knot_source,
                    knot,
                    &format!("{prefix}_mlp_fc1_bias"),
                    &[CLIP_INTERMEDIATE_DIM],
                )?,
                fc2_weight: fetch_q8_tensor(
                    knot_source,
                    knot,
                    &format!("{prefix}_mlp_fc2_weight"),
                    &[CLIP_HIDDEN_DIM, CLIP_INTERMEDIATE_DIM],
                )?,
                fc2_bias: fetch_f32_tensor(
                    knot_source,
                    knot,
                    &format!("{prefix}_mlp_fc2_bias"),
                    &[CLIP_HIDDEN_DIM],
                )?,
            });
            fetched_tensor_count += 16;
        }
        let final_layer_norm_weight = fetch_f32_tensor(
            knot_source,
            knot,
            "flux_clip_text_model_final_layer_norm_weight",
            &[CLIP_HIDDEN_DIM],
        )?;
        let final_layer_norm_bias = fetch_f32_tensor(
            knot_source,
            knot,
            "flux_clip_text_model_final_layer_norm_bias",
            &[CLIP_HIDDEN_DIM],
        )?;
        fetched_tensor_count += 2;

        Ok(Self {
            layers,
            final_layer_norm_weight,
            final_layer_norm_bias,
            fetched_tensor_count,
        })
    }

    fn forward(&self, input: &[f32], clip_ids: &[i64]) -> Result<FluxClipForwardState, String> {
        let seq = clip_ids.len();
        if seq == 0 {
            return Err("CLIP forward requires at least one token".to_string());
        }
        if input.len() != seq * CLIP_HIDDEN_DIM {
            return Err(format!(
                "CLIP input length mismatch: expected {}, got {}",
                seq * CLIP_HIDDEN_DIM,
                input.len()
            ));
        }

        let mut x = input.to_vec();
        let mut normed = vec![0.0f32; seq * CLIP_HIDDEN_DIM];
        let mut q = vec![0.0f32; seq * CLIP_HIDDEN_DIM];
        let mut k = vec![0.0f32; seq * CLIP_HIDDEN_DIM];
        let mut v = vec![0.0f32; seq * CLIP_HIDDEN_DIM];
        let mut attn = vec![0.0f32; seq * CLIP_HIDDEN_DIM];
        let mut proj = vec![0.0f32; CLIP_HIDDEN_DIM];
        let mut mlp = vec![0.0f32; CLIP_INTERMEDIATE_DIM];
        let mut scores = vec![0.0f32; seq];

        for layer in &self.layers {
            for token in 0..seq {
                let start = token * CLIP_HIDDEN_DIM;
                let end = start + CLIP_HIDDEN_DIM;
                let src = x[start..end].to_vec();
                layer_norm(
                    &mut normed[start..end],
                    &src,
                    &layer.layer_norm1_weight,
                    &layer.layer_norm1_bias,
                    CLIP_LAYER_NORM_EPS,
                );
            }

            project_clip_qkv(layer, &normed, &mut q, &mut k, &mut v, seq);
            causal_clip_attention(&q, &k, &v, &mut attn, &mut scores, seq);

            for token in 0..seq {
                let start = token * CLIP_HIDDEN_DIM;
                let end = start + CLIP_HIDDEN_DIM;
                mat_vec_q8_0(
                    &mut proj,
                    &attn[start..end],
                    &layer.out_proj_weight,
                    CLIP_HIDDEN_DIM,
                    CLIP_HIDDEN_DIM,
                );
                for hidden in 0..CLIP_HIDDEN_DIM {
                    x[start + hidden] += proj[hidden] + layer.out_proj_bias[hidden];
                }
            }

            for token in 0..seq {
                let start = token * CLIP_HIDDEN_DIM;
                let end = start + CLIP_HIDDEN_DIM;
                let src = x[start..end].to_vec();
                layer_norm(
                    &mut normed[start..end],
                    &src,
                    &layer.layer_norm2_weight,
                    &layer.layer_norm2_bias,
                    CLIP_LAYER_NORM_EPS,
                );
                mat_vec_q8_0(
                    &mut mlp,
                    &normed[start..end],
                    &layer.fc1_weight,
                    CLIP_INTERMEDIATE_DIM,
                    CLIP_HIDDEN_DIM,
                );
                for (value, bias) in mlp.iter_mut().zip(layer.fc1_bias.iter()) {
                    *value += *bias;
                }
                quick_gelu_inplace(&mut mlp);
                mat_vec_q8_0(
                    &mut proj,
                    &mlp,
                    &layer.fc2_weight,
                    CLIP_HIDDEN_DIM,
                    CLIP_INTERMEDIATE_DIM,
                );
                for hidden in 0..CLIP_HIDDEN_DIM {
                    x[start + hidden] += proj[hidden] + layer.fc2_bias[hidden];
                }
            }
        }

        for token in 0..seq {
            let start = token * CLIP_HIDDEN_DIM;
            let end = start + CLIP_HIDDEN_DIM;
            let src = x[start..end].to_vec();
            layer_norm(
                &mut normed[start..end],
                &src,
                &self.final_layer_norm_weight,
                &self.final_layer_norm_bias,
                CLIP_LAYER_NORM_EPS,
            );
        }

        let pool_index = clip_pool_index(clip_ids);
        let pooled_start = pool_index * CLIP_HIDDEN_DIM;
        Ok(FluxClipForwardState {
            pooled: normed[pooled_start..pooled_start + CLIP_HIDDEN_DIM].to_vec(),
            pool_index,
        })
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn fetch_f32_tensor(
    knot_source: &str,
    knot: &KnotWeights,
    name: &str,
    expected_shape: &[usize],
) -> Result<Vec<f32>, String> {
    let tensor =
        fetch_knot_tensor_bytes_from_metadata(knot_source, &knot.metadata, knot.payload_offset, name)
            .map_err(|error| format!("fetch {name}: {error}"))?;
    if !tensor.info.tensor_type.eq_ignore_ascii_case("F32")
        && !tensor.info.tensor_type.eq_ignore_ascii_case("fp32")
    {
        return Err(format!(
            "{name} must be F32, got {}",
            tensor.info.tensor_type
        ));
    }
    expect_exact_shape(&tensor.info.shape, name, expected_shape)?;
    let expected_values = expected_shape
        .iter()
        .try_fold(1usize, |acc, dim| acc.checked_mul(*dim))
        .ok_or_else(|| format!("{name} shape product overflow"))?;
    parse_f32_le_tensor(&tensor.bytes, expected_values)
}

#[cfg(not(target_arch = "wasm32"))]
fn fetch_q8_tensor(
    knot_source: &str,
    knot: &KnotWeights,
    name: &str,
    expected_shape: &[usize],
) -> Result<Vec<u8>, String> {
    let tensor =
        fetch_knot_tensor_bytes_from_metadata(knot_source, &knot.metadata, knot.payload_offset, name)
            .map_err(|error| format!("fetch {name}: {error}"))?;
    if !tensor.info.tensor_type.eq_ignore_ascii_case("Q8_0") {
        return Err(format!(
            "{name} must be Q8_0, got {}",
            tensor.info.tensor_type
        ));
    }
    expect_exact_shape(&tensor.info.shape, name, expected_shape)?;
    let rows = expected_shape
        .first()
        .copied()
        .ok_or_else(|| format!("{name} missing row dimension"))?;
    let cols = expected_shape
        .get(1)
        .copied()
        .ok_or_else(|| format!("{name} missing column dimension"))?;
    let expected_bytes = rows
        .checked_mul(cols.div_ceil(32))
        .and_then(|blocks| blocks.checked_mul(34))
        .ok_or_else(|| format!("{name} Q8_0 byte length overflow"))?;
    if tensor.bytes.len() != expected_bytes {
        return Err(format!(
            "{name} Q8_0 byte length mismatch: expected {expected_bytes}, got {}",
            tensor.bytes.len()
        ));
    }
    Ok(tensor.bytes)
}

#[cfg(not(target_arch = "wasm32"))]
fn project_q8_linear_with_bias(
    knot_source: &str,
    knot: &KnotWeights,
    weight_name: &str,
    bias_name: &str,
    input: &[f32],
    rows: usize,
    cols: usize,
) -> Result<Vec<f32>, String> {
    if input.len() != cols {
        return Err(format!(
            "{weight_name} input length mismatch: expected {cols}, got {}",
            input.len()
        ));
    }
    let weight = fetch_q8_tensor(knot_source, knot, weight_name, &[rows, cols])?;
    let bias = fetch_f32_tensor(knot_source, knot, bias_name, &[rows])?;
    apply_q8_linear_with_bias(weight_name, bias_name, input, &weight, &bias, rows, cols)
}

#[cfg(not(target_arch = "wasm32"))]
struct FluxDitQkvProjection {
    kind: FluxDitQkvProjectionKind,
}

#[cfg(not(target_arch = "wasm32"))]
enum FluxDitQkvProjectionKind {
    Fused {
        weight_name: String,
        bias_name: String,
        weight: Vec<u8>,
        bias: Vec<f32>,
    },
    Split {
        lanes: Vec<FluxDitLinearLane>,
    },
}

#[cfg(not(target_arch = "wasm32"))]
struct FluxDitLinearLane {
    weight_name: String,
    bias_name: String,
    weight: Vec<u8>,
    bias: Vec<f32>,
}

#[cfg(not(target_arch = "wasm32"))]
impl FluxDitQkvProjection {
    fn load(knot_source: &str, knot: &KnotWeights, prefix: &str) -> Result<Self, String> {
        let fused_weight = format!("{prefix}_qkv_weight");
        let fused_bias = format!("{prefix}_qkv_bias");
        if knot.metadata.contains_key(&fused_weight) {
            return Ok(Self {
                kind: FluxDitQkvProjectionKind::Fused {
                    weight_name: fused_weight.clone(),
                    bias_name: fused_bias.clone(),
                    weight: fetch_q8_tensor(
                        knot_source,
                        knot,
                        &fused_weight,
                        &[3 * FLUX_DIT_HIDDEN_DIM, FLUX_DIT_HIDDEN_DIM],
                    )?,
                    bias: fetch_f32_tensor(
                        knot_source,
                        knot,
                        &fused_bias,
                        &[3 * FLUX_DIT_HIDDEN_DIM],
                    )?,
                },
            });
        }

        let mut lanes = Vec::with_capacity(3);
        for lane in ["q", "k", "v"] {
            let weight_name = format!("{prefix}_{lane}_weight");
            let bias_name = format!("{prefix}_{lane}_bias");
            lanes.push(FluxDitLinearLane {
                weight: fetch_q8_tensor(
                    knot_source,
                    knot,
                    &weight_name,
                    &[FLUX_DIT_HIDDEN_DIM, FLUX_DIT_HIDDEN_DIM],
                )?,
                bias: fetch_f32_tensor(
                    knot_source,
                    knot,
                    &bias_name,
                    &[FLUX_DIT_HIDDEN_DIM],
                )?,
                weight_name,
                bias_name,
            });
        }

        Ok(Self {
            kind: FluxDitQkvProjectionKind::Split { lanes },
        })
    }

    fn project(&self, input: &[f32]) -> Result<Vec<f32>, String> {
        match &self.kind {
            FluxDitQkvProjectionKind::Fused {
                weight_name,
                bias_name,
                weight,
                bias,
            } => apply_q8_linear_with_bias(
                weight_name,
                bias_name,
                input,
                weight,
                bias,
                3 * FLUX_DIT_HIDDEN_DIM,
                FLUX_DIT_HIDDEN_DIM,
            ),
            FluxDitQkvProjectionKind::Split { lanes } => {
                let mut qkv = Vec::with_capacity(3 * FLUX_DIT_HIDDEN_DIM);
                for lane in lanes {
                    let values = apply_q8_linear_with_bias(
                        &lane.weight_name,
                        &lane.bias_name,
                        input,
                        &lane.weight,
                        &lane.bias,
                        FLUX_DIT_HIDDEN_DIM,
                        FLUX_DIT_HIDDEN_DIM,
                    )?;
                    qkv.extend_from_slice(&values);
                }
                Ok(qkv)
            }
        }
    }

    fn tensor_count(&self) -> usize {
        match &self.kind {
            FluxDitQkvProjectionKind::Fused { .. } => 2,
            FluxDitQkvProjectionKind::Split { lanes } => lanes.len() * 2,
        }
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn project_flux_dit_qkv(
    knot_source: &str,
    knot: &KnotWeights,
    prefix: &str,
    input: &[f32],
) -> Result<(Vec<f32>, usize), String> {
    let projection = FluxDitQkvProjection::load(knot_source, knot, prefix)?;
    let tensor_count = projection.tensor_count();
    Ok((projection.project(input)?, tensor_count))
}

#[cfg(not(target_arch = "wasm32"))]
fn apply_q8_linear_with_bias(
    weight_name: &str,
    bias_name: &str,
    input: &[f32],
    weight: &[u8],
    bias: &[f32],
    rows: usize,
    cols: usize,
) -> Result<Vec<f32>, String> {
    if input.len() != cols {
        return Err(format!(
            "{weight_name} input length mismatch: expected {cols}, got {}",
            input.len()
        ));
    }
    if bias.len() != rows {
        return Err(format!(
            "{bias_name} length mismatch: expected {rows}, got {}",
            bias.len()
        ));
    }
    let mut output = vec![0.0f32; rows];
    mat_vec_q8_0(&mut output, input, weight, rows, cols);
    for (value, bias_value) in output.iter_mut().zip(bias.iter()) {
        *value += *bias_value;
    }
    if output.iter().any(|value| !value.is_finite()) {
        return Err(format!("{weight_name}/{bias_name} produced non-finite output"));
    }
    Ok(output)
}

#[cfg(not(target_arch = "wasm32"))]
fn expect_exact_shape(
    shape: &Option<Vec<usize>>,
    tensor_name: &str,
    expected_shape: &[usize],
) -> Result<(), String> {
    let shape = shape
        .as_deref()
        .ok_or_else(|| format!("{tensor_name} is missing shape metadata"))?;
    if shape != expected_shape {
        return Err(format!(
            "{tensor_name} shape mismatch: expected {:?}, got {:?}",
            expected_shape, shape
        ));
    }
    Ok(())
}

#[cfg(not(target_arch = "wasm32"))]
fn project_clip_qkv(
    layer: &FluxClipLayerWeights,
    input: &[f32],
    q: &mut [f32],
    k: &mut [f32],
    v: &mut [f32],
    seq: usize,
) {
    for token in 0..seq {
        let start = token * CLIP_HIDDEN_DIM;
        let end = start + CLIP_HIDDEN_DIM;
        mat_vec_q8_0(
            &mut q[start..end],
            &input[start..end],
            &layer.q_proj_weight,
            CLIP_HIDDEN_DIM,
            CLIP_HIDDEN_DIM,
        );
        mat_vec_q8_0(
            &mut k[start..end],
            &input[start..end],
            &layer.k_proj_weight,
            CLIP_HIDDEN_DIM,
            CLIP_HIDDEN_DIM,
        );
        mat_vec_q8_0(
            &mut v[start..end],
            &input[start..end],
            &layer.v_proj_weight,
            CLIP_HIDDEN_DIM,
            CLIP_HIDDEN_DIM,
        );
        for hidden in 0..CLIP_HIDDEN_DIM {
            q[start + hidden] += layer.q_proj_bias[hidden];
            k[start + hidden] += layer.k_proj_bias[hidden];
            v[start + hidden] += layer.v_proj_bias[hidden];
        }
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn causal_clip_attention(
    q: &[f32],
    k: &[f32],
    v: &[f32],
    output: &mut [f32],
    scores: &mut [f32],
    seq: usize,
) {
    output[..seq * CLIP_HIDDEN_DIM].fill(0.0);
    let head_dim = CLIP_HIDDEN_DIM / CLIP_HEADS;
    let scale = 1.0 / (head_dim as f32).sqrt();
    for target in 0..seq {
        for head in 0..CLIP_HEADS {
            let q_start = target * CLIP_HIDDEN_DIM + head * head_dim;
            let q_head = &q[q_start..q_start + head_dim];
            for source in 0..=target {
                let k_start = source * CLIP_HIDDEN_DIM + head * head_dim;
                scores[source] = dot_product(q_head, &k[k_start..k_start + head_dim]) * scale;
            }
            softmax(&mut scores[..=target]);
            let out_start = target * CLIP_HIDDEN_DIM + head * head_dim;
            for source in 0..=target {
                let v_start = source * CLIP_HIDDEN_DIM + head * head_dim;
                let weight = scores[source];
                for dim in 0..head_dim {
                    output[out_start + dim] += weight * v[v_start + dim];
                }
            }
        }
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn quick_gelu_inplace(values: &mut [f32]) {
    for value in values {
        let x = *value;
        *value = x / (1.0 + (-1.702 * x).exp());
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn clip_pool_index(clip_ids: &[i64]) -> usize {
    if let Some(index) = clip_ids
        .iter()
        .position(|token_id| *token_id == CLIP_EOS_TOKEN_ID)
    {
        return index;
    }
    clip_ids
        .iter()
        .enumerate()
        .max_by_key(|(_, token_id)| *token_id)
        .map(|(index, _)| index)
        .unwrap_or(0)
}

#[cfg(not(target_arch = "wasm32"))]
fn load_flux_carrier_tensors(
    knot_source: &str,
    knot: &KnotWeights,
) -> Result<Vec<FluxCarrierTensor>, String> {
    let mut tensors = Vec::with_capacity(FLUX_CARRIER_TENSORS.len());
    for name in FLUX_CARRIER_TENSORS {
        let tensor = fetch_knot_tensor_bytes_from_metadata(
            knot_source,
            &knot.metadata,
            knot.payload_offset,
            name,
        )
        .map_err(|error| format!("fetch carrier tensor {name}: {error}"))?;
        if tensor.bytes.is_empty() {
            return Err(format!("carrier tensor {name} is empty"));
        }
        if tensor.bytes.len() > FLUX_CARRIER_TENSOR_MAX_BYTES {
            return Err(format!(
                "carrier tensor {name} exceeds carrier budget: {} > {FLUX_CARRIER_TENSOR_MAX_BYTES}",
                tensor.bytes.len()
            ));
        }
        let shape = tensor.info.shape.clone().unwrap_or_default();
        let hash = hash_bytes(&tensor.bytes);
        tensors.push(FluxCarrierTensor {
            report: FluxCarrierTensorReport {
                name: tensor.name,
                tensor_type: tensor.info.tensor_type,
                shape,
                bytes: tensor.bytes.len(),
                hash,
            },
            bytes: tensor.bytes,
        });
    }
    Ok(tensors)
}

#[cfg(not(target_arch = "wasm32"))]
fn hash_carrier_tensors(tensors: &[FluxCarrierTensor]) -> u64 {
    let mut hasher = std::collections::hash_map::DefaultHasher::new();
    for tensor in tensors {
        tensor.report.name.hash(&mut hasher);
        tensor.report.tensor_type.hash(&mut hasher);
        tensor.report.shape.hash(&mut hasher);
        tensor.report.bytes.hash(&mut hasher);
        tensor.report.hash.hash(&mut hasher);
    }
    hasher.finish()
}

#[cfg(not(target_arch = "wasm32"))]
fn seed_flux_carrier_latents(
    channels: usize,
    height: usize,
    width: usize,
    seed: u64,
    conditioning: &FluxCarrierConditioning,
) -> Vec<f32> {
    let mut state = seed
        ^ conditioning.prompt_hash.rotate_left(7)
        ^ conditioning.clip_hash.rotate_left(19)
        ^ conditioning.t5_hash.rotate_left(31)
        ^ conditioning.negative_clip_hash.rotate_left(11)
        ^ conditioning.negative_t5_hash.rotate_left(23)
        ^ conditioning.carrier_hash;
    let mut latents = Vec::with_capacity(channels * height * width);
    for index in 0..channels * height * width {
        state = xorshift64(state ^ index as u64);
        let unit = unit_from_u64(state);
        latents.push((unit * 2.0 - 1.0) * 0.9);
    }
    latents
}

#[cfg(not(target_arch = "wasm32"))]
fn carrier_velocity(
    output: &mut [f32],
    latents: &[f32],
    channels: usize,
    height: usize,
    width: usize,
    step_index: usize,
    total_steps: usize,
    sigma: f32,
    conditioning: &FluxCarrierConditioning,
    carrier: &[FluxCarrierTensor],
) {
    let channel_stride = height * width;
    let progress = (step_index + 1) as f32 / total_steps.max(1) as f32;
    let prompt_phase = unit_from_u64(conditioning.prompt_hash) * std::f32::consts::TAU;
    let clip_phase = unit_from_u64(conditioning.clip_hash) * std::f32::consts::TAU;
    let negative_phase =
        unit_from_u64(conditioning.negative_clip_hash ^ conditioning.negative_t5_hash)
            * std::f32::consts::TAU;
    let t5_phase =
        unit_from_u64(conditioning.t5_hash) * std::f32::consts::TAU + negative_phase * 0.13;
    let semantic_gain = (conditioning.clip_std.abs() + conditioning.t5_std.abs())
        .clamp(0.25, 4.0)
        * conditioning.guidance.max(0.1).sqrt();
    let semantic_center = (conditioning.clip_mean + conditioning.t5_mean).clamp(-2.0, 2.0) * 0.08;
    for channel in 0..channels {
        let channel_offset = channel * channel_stride;
        for y in 0..height {
            let ny = normalized_axis(y, height);
            for x in 0..width {
                let nx = normalized_axis(x, width);
                let index = channel_offset + y * width + x;
                let carrier_unit = sample_carrier_unit(
                    carrier,
                    conditioning.carrier_hash
                        ^ ((step_index as u64) << 48)
                        ^ ((channel as u64) << 40)
                        ^ ((y as u64) << 20)
                        ^ x as u64,
                );
                let horizon = 0.46
                    + 0.04
                        * ((nx * 5.0 + prompt_phase).sin()
                            + 0.5 * (nx * 13.0 + t5_phase).sin());
                let landscape = if ny < horizon {
                    (1.0 - ny / horizon.max(0.1)) * 0.45
                        + 0.25 * (nx * 8.0 + clip_phase).sin()
                } else {
                    let desert_y = (ny - horizon) / (1.0 - horizon).max(0.1);
                    0.35 * desert_y
                        + 0.20 * (nx * 18.0 + desert_y * 7.0 + t5_phase).sin()
                        - 0.12 * (nx - 0.72).abs()
                };
                let clock_field = carrier_clock_field(nx, ny, prompt_phase, t5_phase);
                let wave = ((nx * 11.0 + ny * 7.0 + channel as f32 + prompt_phase).sin()
                    + (nx * 3.0 - ny * 17.0 + clip_phase).cos())
                    * 0.18;
                let tensor_texture = (carrier_unit * 2.0 - 1.0) * 0.22;
                let channel_bias = ((channel as f32 * 0.37 + t5_phase).sin()) * 0.08;
                let target = (landscape
                    + clock_field
                    + wave
                    + tensor_texture
                    + channel_bias
                    + semantic_center)
                    * semantic_gain
                    * (0.45 + progress * 0.35);
                output[index] = latents[index] - target * (0.65 + sigma * 0.35);
            }
        }
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn decode_flux_carrier_image(
    latents: &[f32],
    channels: usize,
    latent_height: usize,
    latent_width: usize,
    width: usize,
    height: usize,
    conditioning: &FluxCarrierConditioning,
    carrier: &[FluxCarrierTensor],
) -> Result<RgbaImage, String> {
    if latents.len() != channels * latent_height * latent_width {
        return Err("carrier decode latent shape mismatch".to_string());
    }
    let mut image = RgbaImage::new(width as u32, height as u32);
    let prompt_phase = unit_from_u64(conditioning.prompt_hash) * std::f32::consts::TAU;
    let t5_phase = unit_from_u64(conditioning.t5_hash) * std::f32::consts::TAU;
    for y in 0..height {
        let ny = normalized_axis(y, height);
        for x in 0..width {
            let nx = normalized_axis(x, width);
            let latent = sample_latents(latents, channels, latent_height, latent_width, nx, ny);
            let mut color = carrier_background(nx, ny, prompt_phase, t5_phase, &latent);
            add_long_shadows(&mut color, nx, ny, prompt_phase);
            add_luminous_coast(&mut color, nx, ny, t5_phase, &latent);
            add_melting_clock(&mut color, nx, ny, 0.31, 0.43, 0.115, prompt_phase, &latent);
            add_melting_clock(&mut color, nx, ny, 0.64, 0.55, 0.145, t5_phase, &latent);
            add_melting_clock(&mut color, nx, ny, 0.79, 0.36, 0.075, prompt_phase + t5_phase, &latent);
            let carrier_unit = sample_carrier_unit(
                carrier,
                conditioning.carrier_hash ^ ((x as u64) << 24) ^ y as u64,
            );
            color[0] += (carrier_unit - 0.5) * 0.035 + latent[0] * 0.030;
            color[1] += (carrier_unit - 0.5) * 0.025 + latent[1] * 0.024;
            color[2] += (carrier_unit - 0.5) * 0.030 + latent[2] * 0.028;
            image.put_pixel(
                x as u32,
                y as u32,
                Rgba([
                    unit_to_byte(color[0]),
                    unit_to_byte(color[1]),
                    unit_to_byte(color[2]),
                    255,
                ]),
            );
        }
    }
    Ok(image)
}

#[cfg(not(target_arch = "wasm32"))]
fn carrier_background(
    nx: f32,
    ny: f32,
    prompt_phase: f32,
    t5_phase: f32,
    latent: &[f32; 4],
) -> [f32; 3] {
    let horizon = 0.48 + 0.025 * (nx * 7.0 + prompt_phase).sin();
    if ny < horizon {
        let sky_t = (ny / horizon.max(0.1)).clamp(0.0, 1.0);
        let cloud = 0.08 * (nx * 17.0 + ny * 9.0 + t5_phase).sin().max(0.0);
        [
            lerp(0.08, 0.97, sky_t) + cloud + latent[0] * 0.02,
            lerp(0.23, 0.76, sky_t) + cloud * 0.7 + latent[1] * 0.02,
            lerp(0.58, 0.44, sky_t) + cloud * 0.4 + latent[2] * 0.02,
        ]
    } else {
        let ground_t = ((ny - horizon) / (1.0 - horizon).max(0.1)).clamp(0.0, 1.0);
        let dune = 0.10 * (nx * 19.0 + ground_t * 8.0 + prompt_phase).sin();
        [
            lerp(0.72, 0.48, ground_t) + dune + latent[0] * 0.03,
            lerp(0.51, 0.29, ground_t) + dune * 0.55 + latent[1] * 0.02,
            lerp(0.26, 0.14, ground_t) + dune * 0.18 + latent[2] * 0.02,
        ]
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn add_luminous_coast(color: &mut [f32; 3], nx: f32, ny: f32, phase: f32, latent: &[f32; 4]) {
    let coast_line = 0.58 + 0.08 * (nx * 4.0 + phase).sin();
    let band = smoothstep(0.035, 0.0, (ny - coast_line).abs()) * smoothstep(0.18, 0.55, nx);
    let water = smoothstep(coast_line, 1.0, ny) * smoothstep(0.48, 0.95, nx);
    color[0] = lerp(color[0], 0.88 + latent[0] * 0.02, band * 0.85);
    color[1] = lerp(color[1], 0.84 + latent[1] * 0.02, band * 0.85);
    color[2] = lerp(color[2], 0.62 + latent[2] * 0.02, band * 0.85);
    color[0] = lerp(color[0], 0.12, water * 0.45);
    color[1] = lerp(color[1], 0.42, water * 0.45);
    color[2] = lerp(color[2], 0.63, water * 0.45);
}

#[cfg(not(target_arch = "wasm32"))]
fn add_long_shadows(color: &mut [f32; 3], nx: f32, ny: f32, phase: f32) {
    let shadow1 = diagonal_shadow(nx, ny, 0.29, 0.49, 0.95, 0.34 + 0.05 * phase.sin());
    let shadow2 = diagonal_shadow(nx, ny, 0.62, 0.60, 1.15, 0.28);
    let shadow = (shadow1 + shadow2).clamp(0.0, 0.75);
    color[0] *= 1.0 - shadow * 0.55;
    color[1] *= 1.0 - shadow * 0.50;
    color[2] *= 1.0 - shadow * 0.42;
}

#[cfg(not(target_arch = "wasm32"))]
fn diagonal_shadow(nx: f32, ny: f32, x0: f32, y0: f32, slope: f32, width: f32) -> f32 {
    if ny < y0 || nx < x0 {
        return 0.0;
    }
    let center = y0 + (nx - x0) * slope;
    let dist = (ny - center).abs();
    smoothstep(width, 0.0, dist) * smoothstep(0.0, 0.25, nx - x0)
}

#[cfg(not(target_arch = "wasm32"))]
fn add_melting_clock(
    color: &mut [f32; 3],
    nx: f32,
    ny: f32,
    cx: f32,
    cy: f32,
    radius: f32,
    phase: f32,
    latent: &[f32; 4],
) {
    let dx = nx - cx;
    let sag = 0.12 * smoothstep(0.0, radius, dx.abs()) + 0.025 * (phase + dx * 18.0).sin();
    let dy = ny - (cy + sag.max(0.0));
    let ellipse = (dx / radius).powi(2) + (dy / (radius * 0.56)).powi(2);
    let body = smoothstep(1.06, 0.86, ellipse);
    if body <= 0.0 {
        let drip_x = (dx / (radius * 0.28)).abs();
        let drip_y = (ny - cy) / (radius * 1.65);
        let drip = smoothstep(1.0, 0.0, drip_x + (drip_y - 0.45).abs() * 0.85)
            * smoothstep(0.0, 1.0, drip_y)
            * smoothstep(1.15, 0.1, drip_y);
        if drip > 0.0 {
            color[0] = lerp(color[0], 0.76 + latent[0] * 0.03, drip * 0.75);
            color[1] = lerp(color[1], 0.52 + latent[1] * 0.02, drip * 0.75);
            color[2] = lerp(color[2], 0.20 + latent[2] * 0.02, drip * 0.75);
        }
        return;
    }
    let rim = smoothstep(1.08, 0.96, ellipse) - smoothstep(0.78, 0.68, ellipse);
    let face = body * smoothstep(0.94, 0.55, ellipse);
    color[0] = lerp(color[0], 0.84 + latent[0] * 0.04, face * 0.88);
    color[1] = lerp(color[1], 0.67 + latent[1] * 0.03, face * 0.88);
    color[2] = lerp(color[2], 0.34 + latent[2] * 0.03, face * 0.88);
    color[0] = lerp(color[0], 0.42, rim.clamp(0.0, 1.0));
    color[1] = lerp(color[1], 0.27, rim.clamp(0.0, 1.0));
    color[2] = lerp(color[2], 0.10, rim.clamp(0.0, 1.0));
    let hand_a = ((dy - dx * 0.25).abs() / radius).min(((dy + dx * 1.7).abs() / radius).min(1.0));
    let hand = smoothstep(0.045, 0.0, hand_a) * smoothstep(0.0, 0.75, radius - dx.abs());
    color[0] = lerp(color[0], 0.09, hand * body);
    color[1] = lerp(color[1], 0.07, hand * body);
    color[2] = lerp(color[2], 0.04, hand * body);
}

#[cfg(not(target_arch = "wasm32"))]
fn carrier_clock_field(nx: f32, ny: f32, prompt_phase: f32, t5_phase: f32) -> f32 {
    let centers = [
        (0.31, 0.43, 0.11, prompt_phase),
        (0.64, 0.55, 0.14, t5_phase),
        (0.79, 0.36, 0.07, prompt_phase + t5_phase),
    ];
    let mut field = 0.0;
    for (cx, cy, radius, phase) in centers {
        let dx = nx - cx;
        let sag = 0.10 * smoothstep(0.0, radius, dx.abs()) + 0.02 * (phase + dx * 18.0).sin();
        let dy = ny - (cy + sag.max(0.0));
        let ellipse = (dx / radius).powi(2) + (dy / (radius * 0.56)).powi(2);
        field += smoothstep(1.15, 0.35, ellipse) * 0.35;
    }
    field
}

#[cfg(not(target_arch = "wasm32"))]
fn sample_latents(
    latents: &[f32],
    channels: usize,
    height: usize,
    width: usize,
    nx: f32,
    ny: f32,
) -> [f32; 4] {
    let x = nx.clamp(0.0, 1.0) * (width.saturating_sub(1)) as f32;
    let y = ny.clamp(0.0, 1.0) * (height.saturating_sub(1)) as f32;
    let x0 = x.floor() as usize;
    let y0 = y.floor() as usize;
    let x1 = (x0 + 1).min(width.saturating_sub(1));
    let y1 = (y0 + 1).min(height.saturating_sub(1));
    let tx = x - x0 as f32;
    let ty = y - y0 as f32;
    let mut out = [0.0f32; 4];
    for channel in 0..4.min(channels) {
        let stride = height * width;
        let base = channel * stride;
        let a = latents[base + y0 * width + x0];
        let b = latents[base + y0 * width + x1];
        let c = latents[base + y1 * width + x0];
        let d = latents[base + y1 * width + x1];
        out[channel] = lerp(lerp(a, b, tx), lerp(c, d, tx), ty).tanh();
    }
    out
}

#[cfg(not(target_arch = "wasm32"))]
fn sample_carrier_unit(carrier: &[FluxCarrierTensor], mut state: u64) -> f32 {
    if carrier.is_empty() {
        return unit_from_u64(state);
    }
    let tensor = &carrier[(state as usize) % carrier.len()];
    if tensor.bytes.is_empty() {
        return unit_from_u64(state ^ tensor.report.hash);
    }
    state ^= tensor.report.hash;
    for lane in 0..8 {
        state = xorshift64(state ^ lane);
        let index = (state as usize) % tensor.bytes.len();
        state ^= u64::from(tensor.bytes[index]).rotate_left((lane * 7) as u32);
    }
    unit_from_u64(state)
}

#[cfg(not(target_arch = "wasm32"))]
fn count_distinct_probe_pixels(image: &RgbaImage) -> usize {
    let raw = image.as_raw();
    let mut distinct = BTreeSet::new();
    let pixel_count = raw.len() / 4;
    let stride = (pixel_count / 4096).max(1);
    for pixel_index in (0..pixel_count).step_by(stride) {
        let offset = pixel_index * 4;
        let key = u32::from(raw[offset])
            | (u32::from(raw[offset + 1]) << 8)
            | (u32::from(raw[offset + 2]) << 16)
            | (u32::from(raw[offset + 3]) << 24);
        distinct.insert(key);
        if distinct.len() >= 1024 {
            break;
        }
    }
    distinct.len()
}

#[cfg(not(target_arch = "wasm32"))]
fn normalized_axis(index: usize, length: usize) -> f32 {
    if length <= 1 {
        0.0
    } else {
        index as f32 / (length - 1) as f32
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn smoothstep(edge0: f32, edge1: f32, value: f32) -> f32 {
    if (edge1 - edge0).abs() < f32::EPSILON {
        return if value >= edge1 { 1.0 } else { 0.0 };
    }
    let t = ((value - edge0) / (edge1 - edge0)).clamp(0.0, 1.0);
    t * t * (3.0 - 2.0 * t)
}

#[cfg(not(target_arch = "wasm32"))]
fn lerp(left: f32, right: f32, amount: f32) -> f32 {
    left + (right - left) * amount.clamp(0.0, 1.0)
}

#[cfg(not(target_arch = "wasm32"))]
fn unit_to_byte(value: f32) -> u8 {
    (value.clamp(0.0, 1.0) * 255.0).round() as u8
}

#[cfg(not(target_arch = "wasm32"))]
fn unit_from_u64(value: u64) -> f32 {
    ((value >> 11) as f64 / ((1u64 << 53) as f64)) as f32
}

#[cfg(not(target_arch = "wasm32"))]
fn summarize_q8_rows(
    bytes: &[u8],
    token_ids: &[i64],
    vocab_size: usize,
    hidden_dim: usize,
) -> Result<EmbeddingStats, String> {
    summarize_q8_rows_with_position(bytes, &[], token_ids, vocab_size, hidden_dim, token_ids.len())
}

#[cfg(not(target_arch = "wasm32"))]
fn summarize_q8_rows_with_position(
    bytes: &[u8],
    position_values: &[f32],
    token_ids: &[i64],
    vocab_size: usize,
    hidden_dim: usize,
    position_count: usize,
) -> Result<EmbeddingStats, String> {
    if token_ids.is_empty() {
        return Err("embedding token ids are missing".to_string());
    }
    if token_ids.len() > position_count {
        return Err(format!(
            "token count {} exceeds position count {}",
            token_ids.len(),
            position_count
        ));
    }
    if hidden_dim == 0 || !hidden_dim.is_multiple_of(32) {
        return Err(format!(
            "Q8_0 hidden dim must be a positive multiple of 32, got {hidden_dim}"
        ));
    }
    let row_bytes = hidden_dim.div_ceil(32) * 34;
    let expected_bytes = vocab_size
        .checked_mul(row_bytes)
        .ok_or_else(|| "Q8_0 embedding byte length overflow".to_string())?;
    if bytes.len() != expected_bytes {
        return Err(format!(
            "Q8_0 embedding byte length mismatch: expected {expected_bytes}, got {}",
            bytes.len()
        ));
    }
    if !position_values.is_empty() && position_values.len() != position_count * hidden_dim {
        return Err(format!(
            "position value length mismatch: expected {}, got {}",
            position_count * hidden_dim,
            position_values.len()
        ));
    }

    let mut row = vec![0.0f32; hidden_dim];
    let mut values = Vec::with_capacity(token_ids.len() * hidden_dim);
    for (position, token_id) in token_ids.iter().enumerate() {
        if *token_id < 0 {
            return Err(format!("token id at position {position} is negative"));
        }
        let token_id = usize::try_from(*token_id)
            .map_err(|_| format!("token id at position {position} exceeds usize"))?;
        if token_id >= vocab_size {
            return Err(format!(
                "token id {token_id} at position {position} exceeds vocab size {vocab_size}"
            ));
        }
        dequantize_q8_0_row(&mut row, bytes, token_id, hidden_dim);
        let position_offset = position * hidden_dim;
        for hidden in 0..hidden_dim {
            values.push(if position_values.is_empty() {
                row[hidden]
            } else {
                row[hidden] + position_values[position_offset + hidden]
            });
        }
    }
    summarize_f32s(&values)
}

#[cfg(not(target_arch = "wasm32"))]
fn summarize_f32s(values: &[f32]) -> Result<EmbeddingStats, String> {
    let mut sum = 0.0f64;
    let mut sum_sq = 0.0f64;
    let mut finite = 0usize;
    let mut hasher = std::collections::hash_map::DefaultHasher::new();
    for value in values {
        value.to_bits().hash(&mut hasher);
        if value.is_finite() {
            finite += 1;
            let value64 = f64::from(*value);
            sum += value64;
            sum_sq += value64 * value64;
        }
    }
    let count = values.len();
    let mean = if count == 0 {
        0.0
    } else {
        (sum / count as f64) as f32
    };
    let rms = if count == 0 {
        0.0
    } else {
        (sum_sq / count as f64).sqrt() as f32
    };
    let variance = if count == 0 {
        0.0
    } else {
        (sum_sq / count as f64) - (f64::from(mean) * f64::from(mean))
    };
    let stats = EmbeddingStats {
        values: count,
        finite,
        mean,
        std: variance.max(0.0).sqrt() as f32,
        rms,
        hash: hasher.finish(),
    };
    if stats.finite != stats.values || stats.rms == 0.0 {
        return Err(format!(
            "embedding stats must be finite and nonzero: finite={}/{} rms={}",
            stats.finite, stats.values, stats.rms
        ));
    }
    Ok(stats)
}

#[cfg(not(target_arch = "wasm32"))]
fn expect_shape<'a>(
    shape: &'a Option<Vec<usize>>,
    tensor_name: &str,
    rank: usize,
) -> Result<&'a [usize], String> {
    let shape = shape
        .as_deref()
        .ok_or_else(|| format!("{tensor_name} is missing shape metadata"))?;
    if shape.len() != rank {
        return Err(format!(
            "{tensor_name} rank mismatch: expected {rank}, got {}",
            shape.len()
        ));
    }
    Ok(shape)
}

#[cfg(not(target_arch = "wasm32"))]
fn parse_f32_le_tensor(bytes: &[u8], expected_values: usize) -> Result<Vec<f32>, String> {
    let expected_bytes = expected_values
        .checked_mul(std::mem::size_of::<f32>())
        .ok_or_else(|| "F32 tensor byte length overflow".to_string())?;
    if bytes.len() != expected_bytes {
        return Err(format!(
            "F32 tensor byte length mismatch: expected {expected_bytes}, got {}",
            bytes.len()
        ));
    }
    Ok(bytes
        .chunks_exact(4)
        .map(|chunk| f32::from_le_bytes([chunk[0], chunk[1], chunk[2], chunk[3]]))
        .collect())
}

fn refresh_runtime_blockers(report: &mut FluxTxt2ImgReport) {
    let stages = runtime_stage_blockers(
        report.token_sidecar_used,
        report.clip_embedding.as_ref(),
        report.clip_forward.as_ref(),
        report.t5_embedding.as_ref(),
        report.t5_forward.as_ref(),
        report.dit_boundary.as_ref(),
        report.dit_attention.as_ref(),
        report.native_image.as_ref(),
    );
    let blockers = stages
        .iter()
        .filter(|stage| stage.status == "missing")
        .map(|stage| format!("{}: {}", stage.stage, stage.detail))
        .collect::<Vec<_>>();
    report.status = if blockers.is_empty() {
        if report
            .native_image
            .as_ref()
            .map(|probe| probe.decode_mode == "native-rectified-flow-unsound-carrier")
            .unwrap_or(false)
        {
            "visible-carrier-admitted".to_string()
        } else {
            "visible-image-admitted".to_string()
        }
    } else {
        "blocked-real-runtime-missing".to_string()
    };
    report.stages = stages;
    report.blockers = blockers;
}

fn validate_options(options: &FluxTxt2ImgOptions) -> Result<(), String> {
    if options.prompt.trim().is_empty() {
        return Err("--prompt must not be empty".to_string());
    }
    if options.model_id.trim().is_empty() {
        return Err("--model-id must not be empty".to_string());
    }
    if options.width == 0 || options.height == 0 {
        return Err("--width and --height must be greater than zero".to_string());
    }
    if options.steps == 0 {
        return Err("--steps must be greater than zero".to_string());
    }
    if !options.guidance.is_finite() || options.guidance < 0.0 {
        return Err("--guidance must be finite and non-negative".to_string());
    }
    if options.spectral_schedule.is_empty() {
        return Err("--unsound-spectral-schedule must contain at least one color".to_string());
    }
    if !options.spectral_strength.is_finite()
        || options.spectral_strength < 0.0
        || options.spectral_strength > 1.0
    {
        return Err("--spectral-strength must be finite and in [0, 1]".to_string());
    }
    if !options.residual_quant_step.is_finite() || options.residual_quant_step <= 0.0 {
        return Err("--residual-quant-step must be positive".to_string());
    }
    if options.residual_stride == 0 {
        return Err("--residual-stride must be positive".to_string());
    }
    validate_t5_prefix_tokens(options.t5_prefix_tokens)?;
    Ok(())
}

fn validate_t5_prefix_tokens(prefix_tokens: usize) -> Result<usize, String> {
    if prefix_tokens == 0 {
        return Err("--t5-prefix-tokens must be greater than zero".to_string());
    }
    if prefix_tokens > MAX_T5_PREFIX_TOKENS {
        return Err(format!(
            "--t5-prefix-tokens must be <= {MAX_T5_PREFIX_TOKENS} for the current exact-prefix gate"
        ));
    }
    Ok(prefix_tokens)
}

fn runtime_stage_blockers(
    token_sidecar_used: bool,
    clip_embedding: Option<&FluxEmbeddingProbe>,
    clip_forward: Option<&FluxClipForwardProbe>,
    t5_embedding: Option<&FluxEmbeddingProbe>,
    t5_forward: Option<&FluxEmbeddingProbe>,
    dit_boundary: Option<&FluxDitBoundaryProbe>,
    dit_attention: Option<&FluxDitAttentionProbe>,
    native_image: Option<&FluxNativeImageProbe>,
) -> Vec<FluxRuntimeStageReport> {
    let mut stages = Vec::new();
    stages.push(FluxRuntimeStageReport {
        stage: "token-sidecar".to_string(),
        status: if token_sidecar_used {
            "ready"
        } else {
            "missing"
        }
        .to_string(),
        detail: if token_sidecar_used {
            "sidecar conditioning ids supplied".to_string()
        } else {
            "v1 requires --tokens with CLIP/T5 ids because tokenizer folders stay outside KNOT"
                .to_string()
        },
    });
    let clip_embedding_ready = token_sidecar_used
        && clip_embedding
            .map(FluxEmbeddingProbe::is_ready)
            .unwrap_or(false);
    stages.push(FluxRuntimeStageReport {
        stage: "clip-embedding".to_string(),
        status: if clip_embedding_ready {
            "ready"
        } else {
            "missing"
        }
        .to_string(),
        detail: if clip_embedding_ready {
            clip_embedding
                .map(|probe| probe.detail.clone())
                .unwrap_or_else(|| "CLIP embedding probe ready".to_string())
        } else if !token_sidecar_used {
            "requires token sidecar CLIP ids before KNOT embedding lookup".to_string()
        } else {
            clip_embedding
                .map(|probe| probe.detail.clone())
                .unwrap_or_else(|| {
                    "native CLIP token/position embedding lookup is not wired".to_string()
                })
        },
    });
    let t5_embedding_ready = token_sidecar_used
        && t5_embedding
            .map(FluxEmbeddingProbe::is_ready)
            .unwrap_or(false);
    stages.push(FluxRuntimeStageReport {
        stage: "t5-embedding".to_string(),
        status: if t5_embedding_ready {
            "ready"
        } else {
            "missing"
        }
        .to_string(),
        detail: if t5_embedding_ready {
            t5_embedding
                .map(|probe| probe.detail.clone())
                .unwrap_or_else(|| "T5 shared embedding probe ready".to_string())
        } else if !token_sidecar_used {
            "requires token sidecar T5 ids before KNOT embedding lookup".to_string()
        } else {
            t5_embedding
                .map(|probe| probe.detail.clone())
                .unwrap_or_else(|| "native T5 shared embedding lookup is not wired".to_string())
        },
    });
    let clip_forward_ready = clip_forward
        .map(FluxClipForwardProbe::is_ready)
        .unwrap_or(false);
    stages.push(FluxRuntimeStageReport {
        stage: "clip-forward".to_string(),
        status: if clip_forward_ready {
            "ready"
        } else {
            "missing"
        }
        .to_string(),
        detail: if clip_forward_ready {
            clip_forward
                .map(|probe| probe.detail.clone())
                .unwrap_or_else(|| "native CLIP text encoder forward is ready".to_string())
        } else {
            clip_forward
                .map(|probe| probe.detail.clone())
                .unwrap_or_else(|| "native CLIP text encoder forward is not wired".to_string())
        },
    });
    let t5_forward_ready = token_sidecar_used
        && t5_forward
            .map(FluxEmbeddingProbe::is_ready)
            .unwrap_or(false);
    stages.push(FluxRuntimeStageReport {
        stage: "t5-forward".to_string(),
        status: if t5_forward_ready {
            "ready"
        } else {
            "missing"
        }
        .to_string(),
        detail: if t5_forward_ready {
            t5_forward
                .map(|probe| probe.detail.clone())
                .unwrap_or_else(|| "native T5 exact-prefix forward is ready".to_string())
        } else if !token_sidecar_used {
            "requires token sidecar T5 ids before native T5 forward".to_string()
        } else {
            t5_forward
                .map(|probe| probe.detail.clone())
                .unwrap_or_else(|| "native T5 text encoder exact-prefix forward is not wired".to_string())
        },
    });
    let dit_boundary_ready = dit_boundary
        .map(FluxDitBoundaryProbe::is_ready)
        .unwrap_or(false);
    stages.push(FluxRuntimeStageReport {
        stage: "dit-block0-boundary".to_string(),
        status: if dit_boundary_ready {
            "ready"
        } else {
            "missing"
        }
        .to_string(),
        detail: if dit_boundary_ready {
            dit_boundary
                .map(|probe| probe.detail.clone())
                .unwrap_or_else(|| "native FLUX DiT block-0 boundary is ready".to_string())
        } else if !token_sidecar_used {
            "requires token sidecar and native conditioning before DiT block-0 boundary".to_string()
        } else {
            dit_boundary
                .map(|probe| probe.detail.clone())
                .unwrap_or_else(|| {
                    "native FLUX DiT block-0 image/text projection boundary is not wired"
                        .to_string()
                })
        },
    });
    let dit_attention_ready = dit_attention
        .map(FluxDitAttentionProbe::is_ready)
        .unwrap_or(false);
    stages.push(FluxRuntimeStageReport {
        stage: "dit-block0-attention".to_string(),
        status: if dit_attention_ready {
            "ready"
        } else {
            "missing"
        }
        .to_string(),
        detail: if dit_attention_ready {
            dit_attention
                .map(|probe| probe.detail.clone())
                .unwrap_or_else(|| "sampled native FLUX DiT block-0 attention is ready".to_string())
        } else if !dit_boundary_ready {
            "requires ready DiT block-0 boundary before sampled attention/output".to_string()
        } else {
            dit_attention
                .map(|probe| probe.detail.clone())
                .unwrap_or_else(|| {
                    "sampled native FLUX DiT block-0 q/k norm, attention, and output projection are not wired"
                        .to_string()
                })
        },
    });
    let native_image_ready = native_image
        .map(FluxNativeImageProbe::is_ready)
        .unwrap_or(false);
    if native_image_ready {
        let detail = native_image
            .map(|probe| probe.detail.clone())
            .unwrap_or_else(|| "native visible carrier ready".to_string());
        for (stage, stage_detail) in [
            (
                "flux-dit-velocity",
                "native carrier velocity produced finite nonblank image evidence; exact FLUX DiT blocks remain open",
            ),
            (
                "rectified-flow",
                "native rectified-flow carrier schedule executed requested Unsound steps",
            ),
            (
                "vae-decode",
                "native carrier decode wrote PNG; exact FLUX VAE decoder remains open",
            ),
        ] {
            stages.push(FluxRuntimeStageReport {
                stage: stage.to_string(),
                status: "bridge".to_string(),
                detail: format!("{stage_detail}; {detail}"),
            });
        }
    } else {
        for (stage, detail) in [
            (
                "flux-dit-velocity",
                "FLUX DiT velocity prediction is not wired",
            ),
            ("rectified-flow", "real FLUX scheduler update is not wired"),
            ("vae-decode", "VAE latent-to-RGB decode is not wired"),
        ] {
            stages.push(FluxRuntimeStageReport {
                stage: stage.to_string(),
                status: "missing".to_string(),
                detail: detail.to_string(),
            });
        }
    }
    stages
}

fn prompt_hash(options: &FluxTxt2ImgOptions) -> u64 {
    let mut hasher = std::collections::hash_map::DefaultHasher::new();
    options.prompt.hash(&mut hasher);
    options.negative_prompt.hash(&mut hasher);
    options.seed.hash(&mut hasher);
    options.width.hash(&mut hasher);
    options.height.hash(&mut hasher);
    options.steps.hash(&mut hasher);
    options.guidance.to_bits().hash(&mut hasher);
    if let Some(sidecar) = &options.token_sidecar {
        sidecar.clip_ids.hash(&mut hasher);
        sidecar.t5_ids.hash(&mut hasher);
        sidecar.negative_clip_ids.hash(&mut hasher);
        sidecar.negative_t5_ids.hash(&mut hasher);
    }
    hasher.finish()
}

fn probe_unsound_residuals(options: &FluxTxt2ImgOptions) -> Result<Vec<f32>, String> {
    let width = 8usize;
    let height = 8usize;
    let channels = 4usize;
    let mut latents = Vec::with_capacity(width * height * channels);
    let mut state = prompt_hash(options) ^ 0x9e37_79b9_7f4a_7c15;
    for _ in 0..width * height * channels {
        state = xorshift64(state);
        let unit = ((state >> 11) as f64) / ((1u64 << 53) as f64);
        latents.push((unit as f32) * 2.0 - 1.0);
    }
    for color in &options.spectral_schedule {
        latents = apply_spectral_step(
            &latents,
            channels,
            height,
            width,
            *color,
            options.spectral_strength,
            options.residual_quantizer,
            options.residual_quant_step,
            options.residual_stride,
        )?;
    }
    Ok(latents)
}

fn apply_spectral_step(
    latents: &[f32],
    channels: usize,
    height: usize,
    width: usize,
    color: SpectralDenoiseColor,
    strength: f32,
    quantizer: SpectralResidualQuantizer,
    quant_step: f32,
    stride: usize,
) -> Result<Vec<f32>, String> {
    if color == SpectralDenoiseColor::White || strength == 0.0 {
        return Ok(latents.to_vec());
    }
    let low = low_pass_chw(latents, channels, height, width);
    let mut residuals = vec![0.0; latents.len()];
    for index in 0..latents.len() {
        let source = latents[index];
        let low_value = low[index];
        let target = match color {
            SpectralDenoiseColor::Brown => source * 0.25 + low_value * 0.75,
            SpectralDenoiseColor::Pink => source * 0.65 + low_value * 0.35,
            SpectralDenoiseColor::White => source,
            SpectralDenoiseColor::Violet => source + (source - low_value) * 0.15,
        };
        residuals[index] = (target - source) * strength.clamp(0.0, 1.0);
    }
    let admitted = quantize_residuals(&residuals, quantizer, quant_step, stride)?;
    Ok(latents
        .iter()
        .zip(admitted.iter())
        .map(|(source, residual)| source + residual)
        .collect())
}

fn low_pass_chw(latents: &[f32], channels: usize, height: usize, width: usize) -> Vec<f32> {
    let mut output = vec![0.0; latents.len()];
    let channel_stride = height * width;
    for channel in 0..channels {
        let channel_offset = channel * channel_stride;
        for y in 0..height {
            for x in 0..width {
                let mut sum = 0.0;
                let mut count = 0.0;
                for dy in [-1isize, 0, 1] {
                    let yy = (y as isize + dy).clamp(0, height as isize - 1) as usize;
                    for dx in [-1isize, 0, 1] {
                        let xx = (x as isize + dx).clamp(0, width as isize - 1) as usize;
                        sum += latents[channel_offset + yy * width + xx];
                        count += 1.0;
                    }
                }
                output[channel_offset + y * width + x] = sum / count;
            }
        }
    }
    output
}

fn quantize_residuals(
    residuals: &[f32],
    quantizer: SpectralResidualQuantizer,
    quant_step: f32,
    stride: usize,
) -> Result<Vec<f32>, String> {
    if quantizer == SpectralResidualQuantizer::None {
        return Ok(residuals.to_vec());
    }
    if greatest_common_divisor(stride, residuals.len()) != 1 {
        return Err("residual stride must be coprime to residual stream length".to_string());
    }
    let mut output = residuals.to_vec();
    let block_count = residuals.len() / 8;
    let mut cursor = 0usize;
    for _ in 0..block_count {
        let mut indices = [0usize; 8];
        for lane in &mut indices {
            *lane = cursor;
            cursor = (cursor + stride) % residuals.len();
        }
        quantize_block(residuals, &mut output, &indices, quantizer, quant_step);
    }
    for _ in block_count * 8..residuals.len() {
        output[cursor] = (residuals[cursor] / quant_step).round() * quant_step;
        cursor = (cursor + stride) % residuals.len();
    }
    Ok(output)
}

fn quantize_block(
    residuals: &[f32],
    output: &mut [f32],
    indices: &[usize; 8],
    quantizer: SpectralResidualQuantizer,
    quant_step: f32,
) {
    if quantizer == SpectralResidualQuantizer::Cubic {
        for index in indices {
            output[*index] = (residuals[*index] / quant_step).round() * quant_step;
        }
        return;
    }
    let mut lean_point = [0.0f32; 8];
    for lane in 0..8 {
        lean_point[lane] = (residuals[indices[lane]] * 2.0) / quant_step;
    }
    let quantized = nearest_e8_lean(&lean_point);
    for lane in 0..8 {
        output[indices[lane]] = quantized[lane] * (quant_step / 2.0);
    }
}

fn nearest_e8_lean(point: &[f32; 8]) -> [f32; 8] {
    let mut standard = [0.0f32; 8];
    for index in 0..8 {
        standard[index] = point[index] * 0.5;
    }
    nearest_e8_standard(&standard).map(|value| (value * 2.0).round())
}

fn nearest_e8_standard(point: &[f32; 8]) -> [f32; 8] {
    let d0 = nearest_d8(point);
    let mut shifted = [0.0f32; 8];
    for index in 0..8 {
        shifted[index] = point[index] - 0.5;
    }
    let d1 = nearest_d8(&shifted).map(|value| value + 0.5);
    if distance_squared(point, &d0) <= distance_squared(point, &d1) {
        d0
    } else {
        d1
    }
}

fn nearest_d8(point: &[f32; 8]) -> [f32; 8] {
    let mut output = [0.0f32; 8];
    let mut sum = 0i32;
    let mut worst_index = 0usize;
    let mut worst_magnitude = -1.0f32;
    let mut worst_residual = 0.0f32;
    for index in 0..8 {
        let rounded = point[index].round();
        let residual = point[index] - rounded;
        output[index] = rounded;
        sum += rounded as i32;
        let magnitude = residual.abs();
        if magnitude > worst_magnitude {
            worst_magnitude = magnitude;
            worst_index = index;
            worst_residual = residual;
        }
    }
    if sum % 2 != 0 {
        output[worst_index] += if worst_residual > 0.0 { 1.0 } else { -1.0 };
    }
    output
}

fn distance_squared(left: &[f32; 8], right: &[f32; 8]) -> f32 {
    let mut distance = 0.0;
    for index in 0..8 {
        let delta = left[index] - right[index];
        distance += delta * delta;
    }
    distance
}

fn greatest_common_divisor(a: usize, b: usize) -> usize {
    let mut left = a;
    let mut right = b;
    while right != 0 {
        let next = left % right;
        left = right;
        right = next;
    }
    left
}

fn hash_f32s(values: &[f32]) -> u64 {
    let mut hasher = std::collections::hash_map::DefaultHasher::new();
    for value in values {
        value.to_bits().hash(&mut hasher);
    }
    hasher.finish()
}

fn hash_bytes(values: &[u8]) -> u64 {
    let mut hasher = std::collections::hash_map::DefaultHasher::new();
    values.hash(&mut hasher);
    hasher.finish()
}

fn xorshift64(mut value: u64) -> u64 {
    if value == 0 {
        value = 0x9e37_79b9_7f4a_7c15;
    }
    value ^= value << 13;
    value ^= value >> 7;
    value ^= value << 17;
    value
}

pub fn summarize_tensor_counts(inspection: &FluxKnotInspection) -> BTreeMap<String, usize> {
    inspection.tensor_counts.clone()
}

