    /// The CARRIER probe report (synthetic knot, no real weights) still fails
    /// closed — it is a probe, not the runtime, and must never claim a visible
    /// image. The REAL runtime lives in `build_flux_real_image` and is now wired
    /// with the basin-gated speculative path (asserted by the companion test
    /// `real_runtime_basin_gate_is_wired_and_fails_closed`). Keeping BOTH honest:
    /// the carrier probe stays blocked; the real gated path executes.
    #[test]
    fn txt2img_report_fails_closed_until_real_runtime_is_wired() {
        let knot = synthetic_flux_knot(true);
        let report = build_flux_txt2img_report(&knot, options("a dali landscape")).unwrap();

        assert_eq!(report.status, "blocked-real-runtime-missing");
        assert!(!report.image_written);
        assert!(!report.is_visible_image_admitted());
        assert!(report
            .blockers
            .iter()
            .any(|blocker| blocker.contains("flux-dit-velocity")));
        assert!(report
            .blockers
            .iter()
            .any(|blocker| blocker.contains("dit-block0-boundary")));
        assert!(!report
            .blockers
            .iter()
            .any(|blocker| blocker.contains("semantic-caption-gate")));
        assert!(require_visible_image_admission(&report).is_err());
    }

    /// THE EVOLUTION MARKER (flipped): the real-runtime basin-gated speculative
    /// path IS now wired into the FLUX flow-match denoise loop
    /// (`build_flux_real_image`). This asserts the gate executes on a real-shaped
    /// velocity residual — admitting a cheap (carry-forward) step when the
    /// accumulated displacement stays inside the certified basin radius, and
    /// MISSING (recompute exact, never lie) the instant it would not. It still
    /// fails closed: a zero radius admits nothing, and the accumulator can never
    /// exceed the basin radius (`net_displacement_within_basin`).
    #[test]
    fn real_runtime_basin_gate_is_wired_and_fails_closed() {
        use crate::basin_gate::RealVelocityGate;

        // Real-shaped FLUX velocity tile: one latent token block (64 channels).
        let v_exact: Vec<f32> = (0..64).map(|i| ((i as f32) * 0.013).sin()).collect();
        // A nearly-identical carry-forward draft (small per-coord drift).
        let v_cheap: Vec<f32> = v_exact.iter().map(|x| x + 0.002).collect();
        let dt = -0.25f32; // a flow-match Euler step size (negative sigma delta)

        // Roomy basin ⇒ the cheap step is certified and admitted.
        let mut g = RealVelocityGate::new(0.5);
        let d = g.offer_step(dt, &v_exact, &v_cheap);
        assert!(d.admitted(), "small drift inside basin must admit the cheap step");
        let rep = g.report();
        assert_eq!(rep.admitted, 1);
        assert!(rep.within_basin(), "accumulated error must stay inside the basin");
        assert!(rep.accumulated > 0.0, "the admitted cheap step advanced the budget");

        // Fail-closed: zero radius admits nothing — the gate degrades to the exact
        // run, never lying.
        let mut g0 = RealVelocityGate::new(0.0);
        assert!(
            !g0.offer_step(dt, &v_exact, &v_cheap).admitted(),
            "zero basin budget must miss (recompute exact), never lie"
        );
        assert_eq!(g0.report().admitted, 0);

        // The accumulator can never cross the basin radius even under a divergent
        // draft (the certified safety invariant).
        let v_far: Vec<f32> = v_exact.iter().map(|x| x + 5.0).collect();
        let mut gt = RealVelocityGate::new(0.1);
        let _ = gt.offer_step(dt, &v_exact, &v_far); // huge residual ⇒ miss
        assert_eq!(gt.report().admitted, 0, "a basin-crossing draft must miss");
        assert!(gt.report().within_basin());
    }

